import { expect } from '@playwright/test';
import { Page } from '@playwright/test';

export class LoginPage {
	constructor(private readonly page: Page) {}

	public get locator() {
		return {
			// Text inputs
			textBoxEmail: this.page.getByLabel('Email'),
			textBoxPassword: this.page.getByLabel('Password'),

			// Buttons
			buttonSubmit: this.page.getByRole('button', { name: 'Login' }),

			// Messages
			messageErrorEmail: this.page.getByText('Invalid email format'),
		};
	}

	async open(): Promise<void> {
		await this.page.goto('/login');
	}

	async fillLoginForm(credentials: { email: string; password: string }): Promise<void> {
		await this.locator.textBoxEmail.fill(credentials.email);
		await this.locator.textBoxPassword.fill(credentials.password);
	}

	async submitForm(): Promise<void> {
		await this.locator.buttonSubmit.click();
	}
}
```

