[Investigation: reCAPTCHA Enterprise Blocks Automated Org Deletion > Affected Code > createCleanupPage helper (`computerOnboarding.test.ts:13-23`)]

```typescript
async function createCleanupPage(browser: Browser) {
	const context = await browser.newContext({ baseURL: ENV.COMPUTER_BASE_URL });
	await context.addInitScript(() => {
		Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
	});
	const cleanupPage = await context.newPage();
	await dismissPromotionalBanners(cleanupPage);
	return { context, cleanupPage };
}
```

