[Page Object Structure > Page Class Template]

```typescript
import { Page, Locator } from '@playwright/test';

export class ExamplePage {
	constructor(private readonly page: Page) {}

	// Locators organized by type
	public get locator() {
		return {
			// Buttons
			buttonSubmit: this.page.getByRole('button', { name: 'Submit' }),
			buttonCancel: this.page.getByRole('button', { name: 'Cancel' }),

			// Text inputs
			textBoxFirstName: this.page.getByLabel('First Name'),
			textBoxLastName: this.page.getByLabel('Last Name'),

			// Links
			linkForgotPassword: this.page.getByRole('link', { name: 'Forgot Password' }),

			// Messages/Text
			messageSuccess: this.page.getByText('Profile updated successfully'),
			messageError: this.page.getByText('Please fill in all required fields'),
		};
	}

	// Business logic methods (action-oriented)
	async fillUserProfile(firstName: string, lastName: string): Promise<void> {
		await this.locator.textBoxFirstName.fill(firstName);
		await this.locator.textBoxLastName.fill(lastName);
	}

	async submitForm(): Promise<void> {
		await this.locator.buttonSubmit.click();
	}

	async waitForSuccessMessage(): Promise<void> {
		await expect(this.locator.messageSuccess).toBeVisible();
	}

	// Navigation method if applicable
	async open(): Promise<void> {
		await this.page.goto('/profile');
	}
}
```

