[Test Structure > Test Template]

```typescript
import { test, expect } from '@fixtures/index.fixtures';

test.describe('Feature Name', { tag: ['@smoke'] }, () => {
	test.beforeEach(async ({ page }) => {
		// Setup - navigate, authenticate, etc.
		await page.goto('/login');
	});

	test('should perform expected behavior with descriptive name', async ({ page, homePage, navigationSideBar }) => {
		// Arrange
		await navigationSideBar.navigateToHome();

		// Act
		await homePage.performAction();

		// Assert
		await expect(page.locator('#result')).toBeVisible();
		await expect(page.locator('#result')).toHaveText('Expected Result');
	});

	test.afterEach(async ({ page }) => {
		// Cleanup if needed
	});
});
```

[Test Structure > Test Best Practices > 1. Descriptive Test Names]

Use full sentences describing expected behavior:

```typescript
// ✅ GOOD
test('should display error message when email format is invalid', async ({ page }) => {
	// ...
});

// ❌ BAD
test('invalid email', async ({ page }) => {
	// ...
});
```

[Test Structure > Test Best Practices > 2. Use Tags]

Apply tags for filtering:

```typescript
test('should login successfully @smoke @authentication', async ({ page }) => {
	// ...
});
```

Common tags: `@smoke`, `@regression`, `@functional`, `@integration`, `@feature-toggle`

[Test Structure > Test Best Practices > 3. Test Independence]

Each test should run independently:

```typescript
// ✅ GOOD - Each test sets up its own state
test('should hide column', async ({ dashboard }) => {
	const table = dashboard(DASHBOARD_NAME).getTableWidget(WIDGETS.table);

	// Explicitly ensure column is visible first
	await table.showColumn('Tickets.Severity');
	await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeVisible();

	// Now test hiding
	await table.hideColumn('Tickets.Severity');
	await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeHidden();
});

// ❌ BAD - Assumes state from previous test
test('should hide column', async ({ dashboard }) => {
	// Assumes column is already visible - FLAKY!
	await table.hideColumn('Tickets.Severity');
});
```

[Test Structure > Test Best Practices > 4. Arrange-Act-Assert Pattern]

```typescript
test('should update user profile', async ({ page, userProfilePage }) => {
	// Arrange - Set up test data and initial state
	const userData = { firstName: 'John', lastName: 'Doe' };
	await page.goto('/profile');

	// Act - Perform the action being tested
	await userProfilePage.updateProfile(userData);

	// Assert - Verify the outcome
	await expect(userProfilePage.locator.messageSuccess).toBeVisible();
});
```

[Test Structure > Test Best Practices > 5. Use Fixtures]

Always import from `@fixtures/index.fixtures`:

```typescript
import { test, expect } from '@fixtures/index.fixtures';

test('example', async ({ page, navigationSideBar, homePage }) => {
	// Fixtures automatically provide page objects and components
});
```

[Test Structure > Test Consolidation & Reliability > When to Consolidate Tests]

Multiple small tests that share the same setup can be consolidated:

```typescript
// ✅ GOOD - Consolidated comprehensive test
test('should display table with all columns, controls, and menu', async ({ page, dashboard }) => {
	const table = dashboard(DASHBOARD_NAME).getTableWidget(WIDGETS.table);

	// Ensure consistent starting state
	await table.showColumn('Tickets.Severity');
	await table.showColumn('Tickets.Stage');

	// Verify all elements
	await expect(table.locator.title).toBeVisible();
	await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeVisible();

	// Verify controls work
	await table.openCustomizeDropdown();
	await expect(table.getCustomizeColumnOption('Tickets.Severity')).toBeVisible();
});

// ❌ BAD - Fragmented tests that depend on each other's state
test('should show severity column', async ({ dashboard }) => {
	/* ... */
});
test('should show stage column', async ({ dashboard }) => {
	/* ... */
}); // May fail if previous test changed state
```

[Test Structure > Test Consolidation & Reliability > Ensuring Consistent State]

```typescript
// ✅ GOOD - Explicitly set state at start of test
test('should support column customization', async ({ dashboard }) => {
	const table = dashboard(DASHBOARD_NAME).getTableWidget(WIDGETS.table);

	// Reset to known state first
	await table.showColumn('Tickets.Severity');
	await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeVisible();

	// Now test the feature
	await table.hideColumn('Tickets.Severity');
	await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeHidden();
});
```

[Test Structure > Test Reliability Principles > ❌ NEVER Weaken Tests to Make Them Pass]

```typescript
// ❌ BAD - Removing assertions to avoid failures
test('should display all columns', async ({ dashboard }) => {
	// Removed column assertions because they were failing
	await expect(table.locator.title).toBeVisible(); // Only checking title
});

// ❌ BAD - Catching errors to prevent test failure
test('should click chart bar', async ({ dashboard }) => {
	try {
		await columnBar.clickFirstDataPoint();
	} catch {
		// Swallowing error to pass
	}
});

// ❌ BAD - Using overly loose assertions
test('should navigate to drillthrough', async ({ page }) => {
	await expect(page).toHaveURL(/.*/); // Matches anything - meaningless
});
```

[Test Structure > Test Reliability Principles > ✅ DO Investigate and Fix Root Cause]

```typescript
// ✅ GOOD - If a column is hidden, explicitly show it first
test('should display all columns', async ({ dashboard }) => {
	const table = dashboard(DASHBOARD_NAME).getTableWidget(WIDGETS.table);

	// Ensure columns are visible (handles state from previous tests)
	await table.showColumn('Tickets.Severity');
	await table.showColumn('Tickets.Stage');

	// Now assert they're visible
	await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeVisible();
	await expect(table.getColumnHeader(/Tickets.Stage/i)).toBeVisible();
});

// ✅ GOOD - Use robust locators that work across environments
test('should click chart bar for drillthrough', async ({ dashboard }) => {
	const columnBar = dashboard(DASHBOARD_NAME).getColumnChartWidget(WIDGETS.columnBar);

	// Target by CSS class, not by data value
	await columnBar.clickFirstDataPointForDrillthrough();
	await ticketsDashboard.assertDrillthroughNavigated(WIDGETS.columnBar);
});
```

