[Common Patterns & Examples > Table Interaction Pattern]

```typescript
import { test, expect } from '@fixtures/index.fixtures';

test('interact with table', async ({ dashboard }) => {
	const table = dashboard('Dashboard Name').getTableWidget('Table Widget');

	// Column visibility
	await table.showColumn('Column Name');
	await table.hideColumn('Another Column');

	// Verify columns
