import path from 'path';
import dotenv from 'dotenv';
import fs from 'fs';
import { SUPPORTED_ENVIRONMENTS, TestEnvironment } from '../src/config/env.config';
import { ENV } from '../src/config/env.config';

async function globalSetup() {
	const rootEnvPath = path.resolve(process.cwd(), '.env');
	if (fs.existsSync(rootEnvPath)) {
		dotenv.config({ path: rootEnvPath });
	}

	ENV.TEST_ENV = process.env.TEST_ENV as TestEnvironment;
	console.log('Test Environment:', ENV.TEST_ENV);

	if (!ENV.TEST_ENV) {
		throw new Error('ERROR: .env file is missing or TEST_ENV variable is not set. Please copy .env.example to .env and fill in the required values.');
	}

	if (!SUPPORTED_ENVIRONMENTS.includes(ENV.TEST_ENV as TestEnvironment)) {
		throw new Error(`ERROR: Unsupported test environment: ${ENV.TEST_ENV}. Supported environments: ${SUPPORTED_ENVIRONMENTS.join(', ')}`);
	}

	const envPath = path.resolve(process.cwd(), `env/.env.${ENV.TEST_ENV}`);
	if (fs.existsSync(envPath)) {
		dotenv.config({ path: envPath });
		console.log(`Loaded environment config from: env/.env.${ENV.TEST_ENV}`);
	}
}

export default globalSetup;

import { Page, Locator, expect, Response } from '@playwright/test';
import { MetricWidget, ColumnChartWidget, TableWidget, PieChartWidget } from './widgets';

export class Dashboard {
	constructor(
		private readonly page: Page,
		private readonly dashboardName: string
	) {}

	public get locator() {
		return {
			header: this.page.getByTestId(this.dashboardName),
			burgerMenuButton: this.page.locator('[data-drid*="DASHBOARD"][data-drid*="action-button"]'),
			shareMenuItem: this.page.getByRole('menuitem', { name: 'Share' }),
			editMenuItem: this.page.getByRole('menuitem', { name: 'Edit' }),
			cloneMenuItem: this.page.getByRole('menuitem', { name: 'Clone' }),
			deleteMenuItem: this.page.getByRole('menuitem', { name: 'Delete' }),
			addWidgetButton: this.page.getByRole('button', { name: /widget/i }),
			saveChangesButton: this.page.getByRole('button', { name: /save changes/i }),
			cancelButton: this.page.getByRole('button', { name: 'Cancel' }),
		};
	}

	// ===============================================
	// Widget Factory Methods
	// ===============================================

	getMetricWidget(widgetName: string): MetricWidget {
		return new MetricWidget(this.page, widgetName);
	}

	getColumnChartWidget(widgetName: string): ColumnChartWidget {
		return new ColumnChartWidget(this.page, widgetName);
	}

	getTableWidget(widgetName: string): TableWidget {
		return new TableWidget(this.page, widgetName);
	}

	getPieChartWidget(widgetName: string): PieChartWidget {
		return new PieChartWidget(this.page, widgetName);
	}

	// ===============================================
	// Dashboard Load Methods
	// ===============================================

	// Sets up response listeners for dashboard data load
	// Call BEFORE navigating to dashboard, await returned promises AFTER navigation
	setupDashboardLoadListeners(options?: { timeoutMs?: number }): {
		dashboardDefinitionPromise: Promise<Response>;
		dataFetchPromises: Promise<Response>[];
		dataStreamPromise: Promise<Response | null>;
	} {
		const { timeoutMs = 120_000 } = options ?? {};

		const dashboardDefinitionPromise = this.page.waitForResponse((resp) => resp.url().includes('dashboards.get') && resp.status() === 200, {
			timeout: timeoutMs,
		});

		const dataFetchPromises = [
			this.page.waitForResponse((resp) => resp.url().includes('oasis.data.fetch') && resp.status() === 200, { timeout: timeoutMs }),
			this.page.waitForResponse((resp) => resp.url().includes('oasis.data.fetch') && resp.status() === 200, { timeout: timeoutMs }),
			this.page.waitForResponse((resp) => resp.url().includes('oasis.data.fetch') && resp.status() === 200, { timeout: timeoutMs }),
		];

		const dataStreamPromise = this.page
			.waitForResponse((resp) => resp.url().includes('oasis.data.stream') && resp.status() === 200, { timeout: timeoutMs })
			.catch(() => null);

		return {
			dashboardDefinitionPromise,
			dataFetchPromises,
			dataStreamPromise,
		};
	}

	async assertDashboardHeaderDisplayed(options?: { timeoutMs?: number }): Promise<void> {
		const { timeoutMs = 60_000 } = options ?? {};
		await expect(this.locator.header).toBeVisible({ timeout: timeoutMs });
	}

	// Verifies URL contains drillthrough path and breadcrumb shows widget name
	async assertDrillthroughNavigated(widgetName: string, options?: { timeoutMs?: number }): Promise<void> {
		const { timeoutMs = 30_000 } = options ?? {};
		await expect(this.page).toHaveURL(/drillthrough/, { timeout: timeoutMs });
		const breadcrumb = this.page.getByText(`${widgetName} (drillthrough)`);
		await expect(breadcrumb).toBeVisible({ timeout: timeoutMs });
	}

	// ===============================================
	// Burger Menu Methods
	// ===============================================

	async openBurgerMenu(): Promise<void> {
		await this.locator.burgerMenuButton.click();
	}

	async closeBurgerMenu(): Promise<void> {
		await this.page.keyboard.press('Escape');
	}

	async openShareDialog(): Promise<void> {
		await this.openBurgerMenu();
		await this.locator.shareMenuItem.click();
	}

	async enterEditMode(): Promise<void> {
		await this.openBurgerMenu();
		await this.locator.editMenuItem.click();
	}

	async openDeleteDialog(): Promise<void> {
		await this.openBurgerMenu();
		await this.locator.deleteMenuItem.click();
	}

	// Validates Share dialog structure using aria snapshot
	async assertShareDialogDisplayed(): Promise<void> {
		const shareDialog = this.page.getByRole('dialog');
		await expect(shareDialog).toBeVisible();
		await expect(shareDialog).toMatchAriaSnapshot(`
			- dialog "Share Dashboard":
			  - heading "Share Dashboard" [level=2]
			  - button "Copy link"
			  - text: Add users or groups
			  - button "Share"
			  - text: /Share via email/
		`);
	}

	async assertEditModeActive(): Promise<void> {
		await expect(this.locator.saveChangesButton).toBeVisible();
		await expect(this.locator.cancelButton).toBeVisible();
		await expect(this.locator.addWidgetButton).toBeVisible();
	}

	// Validates Clone dialog structure using aria snapshot
	async assertCloneDialogDisplayed(): Promise<void> {
		const cloneDialog = this.page.getByRole('dialog');
		await expect(cloneDialog).toBeVisible();
		await expect(cloneDialog).toMatchAriaSnapshot(`
			- dialog "Clone dashboard":
			  - heading "Clone dashboard" [level=2]
			  - textbox
			  - button "Cancel"
			  - button "Clone"
		`);
	}

	async assertCloneDialogHasExpectedName(): Promise<void> {
		const cloneDialog = this.page.getByRole('dialog');
		const expectedName = `${this.dashboardName}(Copy)`;
		await expect(cloneDialog.getByRole('textbox')).toHaveValue(expectedName);
	}

	async confirmClone(): Promise<void> {
		const cloneDialog = this.page.getByRole('dialog');
		await cloneDialog.getByRole('button', { name: 'Clone' }).click();
	}

	// Validates Delete dialog structure using aria snapshot
	async assertDeleteDialogDisplayed(): Promise<void> {
		const deleteDialog = this.page.getByRole('dialog');
		await expect(deleteDialog).toBeVisible();
		await expect(deleteDialog).toMatchAriaSnapshot(`
			- dialog "Delete this dashboard?":
			  - heading "Delete this dashboard?" [level=2]
			  - text: /deleted.*cannot be recovered/
			  - button "Cancel"
			  - button "Delete"
		`);
	}

	async confirmDelete(): Promise<void> {
		const deleteDialog = this.page.getByRole('dialog');
		const confirmButton = deleteDialog.getByRole('button', { name: /delete/i });
		await confirmButton.click();
	}

	async closeDialog(): Promise<void> {
		await this.page.keyboard.press('Escape');
	}

	// ===============================================
	// Widget Management Methods
	// ===============================================

	// Opens Dashboard Builder page for creating a new widget
	async openDashboardBuilder(): Promise<void> {
		await this.locator.addWidgetButton.click();
	}

	getWidgetContainer(widgetName: string): Locator {
		return this.page.locator('.grid-stack-item').filter({ hasText: widgetName });
	}

	async openWidgetMenu(widgetName: string): Promise<void> {
		const widgetContainer = this.getWidgetContainer(widgetName);
		const menuButton = widgetContainer.locator('[data-drid*="action-menu-trigger"]');
		await menuButton.click();
	}

	// Removes a widget via its menu and confirms the removal dialog
	async removeWidget(widgetName: string): Promise<void> {
		await this.openWidgetMenu(widgetName);
		const removeOption = this.page.getByRole('button', { name: 'Remove' });
		await removeOption.click();

		const removeDialog = this.page.getByRole('dialog', { name: 'Remove Widget?' });
		await expect(removeDialog).toBeVisible();
		await removeDialog.getByRole('button', { name: 'Remove Widget' }).click();
	}

	async assertWidgetVisible(widgetName: string): Promise<void> {
		const widgetContainer = this.getWidgetContainer(widgetName).first();
		await expect(widgetContainer).toBeVisible();
	}

	async assertWidgetHidden(widgetName: string): Promise<void> {
		const widgetContainer = this.getWidgetContainer(widgetName).first();
		await expect(widgetContainer).toBeHidden();
	}
}

import { Page, Locator, expect } from '@playwright/test';

export class ColumnChartWidget {
	constructor(
		private readonly page: Page,
		private readonly widgetName: string
	) {}

	public get locator() {
		const widgetContainer = this.page.locator('.grid-stack-item').filter({ hasText: this.widgetName });
		return {
			title: widgetContainer.getByText(this.widgetName),
			widgetContainer,
			chart: widgetContainer.locator('svg, canvas').first(),
			viewMoreLink: widgetContainer.getByText(/View \d+ more/),
			menuButton: widgetContainer.getByTestId(/action-menu-trigger/),
			menu: this.page.getByRole('dialog').first(),
			dataLabels: widgetContainer.locator('.highcharts-data-labels text'),
		};
	}

	// ===============================================
	// Chart Element Methods
	// ===============================================

	getAxisLabel(text: string | RegExp): Locator {
		return this.locator.widgetContainer.getByText(text, { exact: true });
	}

	// Uses data-drid attribute to avoid matching tooltip text
	getLegendItem(name: string): Locator {
		return this.locator.widgetContainer.locator('[data-drid*="legend-item"]').filter({ hasText: name });
	}

	// ===============================================
	// Drillthrough Methods
	// ===============================================

	// Clicks the first bar in series-0 to trigger drillthrough navigation
	async clickFirstDataPointForDrillthrough(): Promise<void> {
		const chartBar = this.locator.widgetContainer.locator('g.highcharts-series-0.highcharts-column-series path.highcharts-point').first();
		await chartBar.click();
	}

	// ===============================================
	// Data Label Methods
	// ===============================================

	// Gets the first data label value as a number
	async getFirstDataLabelValue(): Promise<number> {
		const text = await this.locator.dataLabels.first().textContent();
		return Number(text?.trim() ?? 0);
	}

	// Asserts that data labels are visible and contain numeric values
	async assertDataLabelsVisible(): Promise<void> {
		await expect(this.locator.dataLabels.first()).toBeVisible();
		const value = await this.getFirstDataLabelValue();
		expect(value).toBeGreaterThan(0);
	}

	// ===============================================
	// Tooltip Methods
	// ===============================================

	// Hovers first bar and checks tooltip appears via SVG opacity or HTML tooltip container
	async hoverFirstBarAndAssertTooltip(): Promise<void> {
		const firstBar = this.locator.widgetContainer.locator('g.highcharts-series-0 path.highcharts-point').first();
		await firstBar.hover();

		// tooltip.outside renders HTML tooltip outside the widget container; .or() handles both modes
		const svgTooltip = this.locator.widgetContainer.locator('g.highcharts-tooltip[opacity="1"]');
		const htmlTooltip = this.page.locator('.highcharts-tooltip-container').first();
		await expect(svgTooltip.or(htmlTooltip)).toBeVisible();
	}

	// ===============================================
	// Legend Methods
	// ===============================================

	async toggleLegendItem(legendName: string): Promise<void> {
		await this.getLegendItem(legendName).click();
	}

	// Legend items use data-drid with "--enabled" or "--disabled" suffix
	async assertLegendItemEnabled(legendName: string): Promise<void> {
		const enabledLegend = this.locator.widgetContainer.locator('[data-drid*="legend-item"][data-drid$="--enabled"]').filter({ hasText: legendName });
		await expect(enabledLegend).toBeVisible();
	}

	async assertLegendItemDisabled(legendName: string): Promise<void> {
		const disabledLegend = this.locator.widgetContainer
			.locator('[data-drid*="legend-item"][data-drid$="--disabled"]')
			.filter({ hasText: legendName });
		await expect(disabledLegend).toBeVisible();
	}

	// ===============================================
	// Bar Visibility Methods
	// ===============================================

	// Highcharts sets visibility:hidden on bars when their legend item is toggled off
	async getVisibleBarCount(): Promise<number> {
		const allBars = this.locator.widgetContainer.locator('g.highcharts-series.highcharts-column-series path.highcharts-point');
		const totalBars = await allBars.count();
		let visibleCount = 0;
		for (let i = 0; i < totalBars; i++) {
			const bar = allBars.nth(i);
			const visibility = await bar.evaluate((el) => window.getComputedStyle(el).visibility);
			if (visibility !== 'hidden') {
				visibleCount++;
			}
		}
		return visibleCount;
	}

	async assertVisibleBarCount(expectedCount: number): Promise<void> {
		await expect.poll(async () => await this.getVisibleBarCount(), { timeout: 15000 }).toBe(expectedCount);
	}

	async assertBarsVisible(): Promise<void> {
		const initialCount = await this.getVisibleBarCount();
		expect(initialCount).toBeGreaterThan(0);
	}

	async assertFewerBarsVisible(previousCount: number): Promise<void> {
		await expect.poll(async () => await this.getVisibleBarCount(), { timeout: 15000 }).toBeLessThan(previousCount);
	}

	// ===============================================
	// Menu Methods
	// ===============================================

	async openMenu(): Promise<void> {
		await this.locator.menuButton.click();
	}

	async assertMenuIsDisplayed(options?: { timeoutMs?: number }): Promise<void> {
		const { timeoutMs = 15_000 } = options ?? {};
		await expect(this.locator.menu).toBeVisible({ timeout: timeoutMs });
	}
}

