import { Page, Locator, expect } from '@playwright/test';

export class TableWidget {
	constructor(
		private readonly page: Page,
		private readonly widgetName: string
	) {}

	public get locator() {
		const widgetContainer = this.page.locator('.grid-stack-item').filter({ hasText: this.widgetName });
		return {
			title: widgetContainer.getByText(this.widgetName),
			widgetContainer,
			table: widgetContainer.getByRole('table').or(widgetContainer.getByRole('treegrid')),
			groupDropdown: widgetContainer.getByRole('button', { name: /Group/ }),
			customizeDropdown: widgetContainer.getByRole('button', { name: 'Customize' }),
			menuButton: widgetContainer.getByTestId(/action-menu-trigger/),
			menu: this.page.getByRole('dialog').first(),
			groupSidebar: widgetContainer.getByRole('tree').or(widgetContainer.locator('.group-sidebar')),
			paginationInfo: widgetContainer.getByText(/\d+-\d+ of \d+ items/),
		};
	}

	// ===============================================
	// Column Methods
	// ===============================================

	getColumnHeader(name: string | RegExp): Locator {
		return this.locator.widgetContainer.getByRole('columnheader', { name });
	}

	// Finds the position of a column by matching its header text
	async getColumnIndex(columnName: string): Promise<number> {
		const headers = this.locator.table.getByRole('columnheader');
		const headerCount = await headers.count();

		for (let i = 0; i < headerCount; i++) {
			const headerText = await headers.nth(i).textContent();
			if (headerText?.includes(columnName)) {
				return i;
			}
		}
		return -1;
	}

	async assertColumnVisible(columnName: string): Promise<void> {
		const columnIndex = await this.getColumnIndex(columnName);
		expect(columnIndex, `Column "${columnName}" should be visible in table`).toBeGreaterThanOrEqual(0);
	}

	async assertColumnHidden(columnName: string): Promise<void> {
		const columnIndex = await this.getColumnIndex(columnName);
		expect(columnIndex, `Column "${columnName}" should be hidden from table`).toBe(-1);
	}

	// Retrieves all cell values in a column for validation
	getColumnCellsByIndex(columnIndex: number): Locator {
		return this.locator.table.getByRole('row').locator(`[role="gridcell"]:nth-child(${columnIndex + 1})`);
	}

	// Validates that all rows in a column have the same expected value
	async assertColumnValuesEqual(options: { columnName: string; expectedValue: string }): Promise<void> {
		const { columnName, expectedValue } = options;

		const columnIndex = await this.getColumnIndex(columnName);
		expect(columnIndex, `Column "${columnName}" not found in table`).toBeGreaterThanOrEqual(0);

		const cells = this.getColumnCellsByIndex(columnIndex);
		await expect(cells.first()).toContainText(expectedValue);

		const cellCount = await cells.count();
		expect(cellCount, `No cells found in column "${columnName}"`).toBeGreaterThan(0);

		for (let i = 0; i < cellCount; i++) {
			await expect(cells.nth(i)).toContainText(expectedValue);
		}
	}

	// ===============================================
	// Group Filter Methods
	// ===============================================

	// Locates a group item in the sidebar for clicking or validation
	getGroupItem(name: string): Locator {
		return this.locator.widgetContainer.getByRole('listitem').filter({ hasText: name });
	}

	// Groups the table by a specific field (e.g., "Tickets.Stage")
	async selectGroupOption(option: string): Promise<void> {
		await this.locator.groupDropdown.click();
		await this.page.getByRole('menu', { name: /Group/ }).getByText(option, { exact: true }).click();
	}

	async resetGrouping(): Promise<void> {
		await this.selectGroupOption('None');
	}

	// ===============================================
	// Customize Column Methods
	// ===============================================

	async openCustomizeDropdown(): Promise<Locator> {
		await this.locator.customizeDropdown.click();
		const menu = this.page.getByRole('menu', { name: 'Customize' });
		await expect(menu).toBeVisible();
		return menu;
	}

	// Uses regex to handle variations in accessibility tree text
	getCustomizeColumnOption(columnName: string): Locator {
		const pattern = new RegExp(columnName.replace(/\./g, '\\s*\\.\\s*'), 'i');
		return this.page.getByRole('menu', { name: 'Customize' }).getByRole('menuitem', { name: pattern });
	}

	// Gets the checkbox inside a column option
	private getCustomizeColumnCheckbox(columnName: string): Locator {
		return this.getCustomizeColumnOption(columnName).getByRole('checkbox');
	}

	// Hides a column by unchecking it in the Customize dropdown
	async hideColumn(columnName: string): Promise<void> {
		await this.openCustomizeDropdown();
		const checkbox = this.getCustomizeColumnCheckbox(columnName);
		const isChecked = await checkbox.isChecked();
		if (isChecked) {
			await checkbox.click();
		}
		// Click outside to close the dropdown
		await this.locator.title.click();
	}

	// Shows a column by checking it in the Customize dropdown (idempotent - no-op if already visible)
	async showColumn(columnName: string): Promise<void> {
		await this.openCustomizeDropdown();
		const checkbox = this.getCustomizeColumnCheckbox(columnName);
		const isChecked = await checkbox.isChecked();
		if (!isChecked) {
			await checkbox.click();
		}
		await this.locator.title.click();
	}

	// Shows multiple columns at once
	async showColumns(columnNames: string[]): Promise<void> {
		for (const columnName of columnNames) {
			await this.showColumn(columnName);
		}
	}

	// Asserts all specified column headers are visible
	async assertColumnHeadersVisible(columnPatterns: RegExp[]): Promise<void> {
		for (const pattern of columnPatterns) {
			await expect(this.getColumnHeader(pattern)).toBeVisible();
		}
	}

	// Asserts all specified column options are visible in the Customize dropdown
	async assertCustomizeOptionsVisible(columnNames: string[]): Promise<void> {
		await this.openCustomizeDropdown();
		for (const columnName of columnNames) {
			await expect(this.getCustomizeColumnOption(columnName)).toBeVisible();
		}
		await this.locator.title.click();
	}

	// ===============================================
	// Drillthrough Methods
	// ===============================================

	// Skips header row (index 0), clicks on data row
	async clickRowForDrillthrough(rowIndex: number = 0): Promise<void> {
		const rows = this.locator.table.getByRole('row');
		await rows.nth(rowIndex + 1).click();
	}

	// ===============================================
	// Menu Methods
	// ===============================================

	async openMenu(): Promise<void> {
		await this.locator.menuButton.click();
	}

	async assertMenuIsDisplayed(options?: { timeoutMs?: number }): Promise<void> {
		const { timeoutMs = 15_000 } = options ?? {};
		await expect(this.locator.menu).toBeVisible({ timeout: timeoutMs });
	}
}

