export class GlobalSearchModal {
	constructor(private page: Page) {
		this.page = page;
	}

	public get locator() {
		return {
			// Modal
			modalSearch: this.page.getByTestId('global-search-modal-content'),

			// Textboxes
			searchInput: this.page.getByRole('textbox', { name: 'Type to find tickets,' }),

			// Search results
			searchResults: this.page.locator('[data-drid="search-results"]'),
			searchResultId: this.page.getByTestId('search-results-id'),
			searchResultLoader: this.page.getByTestId('search-results').getByTestId('loader'),

			// Buttons
			buttonFilter: this.page.getByTestId('search-filters--more-filters-button'),

			// Dropdowns
			dropdownFilterMenu: this.page.getByTestId('search-filters--more-filters-select-dropdown-options'),
			dropdownMenuContent: this.page.locator('[role="menu"][data-radix-menu-content]'), // this is the dropdown menu content of selected filters
			createdDateMenu: {
				on: this.page.getByRole('menuitem', { name: 'On' }),
				between: this.page.getByRole('menuitem', { name: 'Between' }),
			},

			datePicker: {
				month: this.page.getByRole('button', { name: 'select month' }),
				year: this.page.getByRole('button', { name: 'select year' }),
			},
		};
	}

	// Opens the global search modal using keyboard shortcut (Cmd+K on Mac, Ctrl+K on Windows/Linux)
	public async open(): Promise<void> {
		const isMac = process.platform === 'darwin';
		await this.page.keyboard.press(isMac ? 'Meta+K' : 'Control+K');

		await expect(this.locator.modalSearch).toBeVisible();
	}

	/**
	 * Performs a search with proper state reset to prevent stale results in retry scenarios.
	 * Waits for the loader to clear existing results before typing new keyword.
	 */
	public async search(keyword: string): Promise<void> {
		const hasExistingResults = await this.hasSearchResults();
		await this.clearSearchInput();
		if (hasExistingResults) {
			await this.waitForSearchResultsToReset();
		}
		await this.locator.searchInput.pressSequentially(keyword);
	}

	private async hasSearchResults(): Promise<boolean> {
		return await this.locator.searchResultId
			.first()
			.isVisible()
			.catch(() => false);
	}

	private async clearSearchInput(): Promise<void> {
		await this.locator.searchInput.clear();
		await expect(this.locator.searchInput).toHaveValue('');
	}

	private async waitForSearchResultsToReset(): Promise<void> {
		await expect(this.locator.searchResultLoader)
			.toBeVisible({ timeout: 2000 })
			.catch(() => {
				// Loader might be too fast to catch, that's okay
			});
		await expect(this.locator.searchResultLoader).toBeHidden({ timeout: 5000 });
	}

	// Expects the top N (default is 5) search results to contain the title
	public async expectTopSearchResultsToContainTitle(searchTitle: string, options?: { timeout?: number; topN?: number }): Promise<void> {
		const { timeout = 30_000, topN = 5 } = options ?? {};

		const topResults = this.page.locator(`(//p[@data-drid="search-results-title"])[position() <= ${topN}]`);
		await topResults.first().waitFor({ state: 'visible', timeout });

		const match = topResults.filter({ hasText: searchTitle });
		await expect(match.first()).toBeVisible({ timeout });
	}

	// Expects the top N (default is 5) search results to contain the id
	public async expectTopSearchResultsToContainId(searchId: string, options?: { timeout?: number; topN?: number }): Promise<void> {
		const { timeout = 30_000, topN = 5 } = options ?? {};

		const topResults = this.page.locator(`(//div[@data-drid="search-results-id"])[position() <= ${topN}]`);
		await topResults.first().waitFor({ state: 'visible', timeout });

		const match = topResults.filter({ hasText: searchId });
		await expect(match.first()).toBeVisible({ timeout });
	}

	// Searches for an issue by ID and verifies it appears in search results with retry logic
	// This handles cases where newly created issues may not be indexed immediately
	public async searchAndVerifyResultById(searchId: string, options?: { timeout?: number; topN?: number }): Promise<void> {
		const { timeout = 90_000, topN = 5 } = options ?? {};

		await expect(async () => {
			await this.search(searchId);
			await this.expectTopSearchResultsToContainId(searchId, { timeout: 5000, topN });
		}).toPass({
			timeout,
			intervals: [1_000, 2_000, 3_000],
		});
	}

	public async clickSearchResultById(searchId: string): Promise<void> {
		await this.locator.searchResultId.filter({ hasText: searchId }).click();
	}
}

