	}

	getSourceCardLink(articleTitle: string): Locator {
		return this.locator.sourcesPanel.getByRole('link').filter({ hasText: articleTitle });
	}

	/**
	 * Clicks a source card link and returns the opened page.
	 * Handles three navigation scenarios:
	 * 1. Link opens directly in a new tab
	 * 2. External link warning dialog appears — click Proceed to open new tab
	 * 3. Internal link navigates within the same page (DOD panel) — no new tab
	 */
	async openSourceCardLink(articleTitle: string): Promise<Page> {
		const newPagePromise = this.page
			.context()
			.waitForEvent('page', { timeout: 5_000 })
			.catch(() => null);

		await this.getSourceCardLink(articleTitle).click();
		let newPage = await newPagePromise;

		// If no new page opened, check for external link warning dialog
		if (!newPage) {
			if (await isVisibleWithinTimeout(this.locator.buttonProceed)) {
				const retryPromise = this.page
					.context()
					.waitForEvent('page', { timeout: 10_000 })
					.catch(() => null);
				await this.locator.buttonProceed.click();
				newPage = await retryPromise;
			}
		}

		// If still no new page, the link navigated in the same page (internal DOD link)
		if (!newPage) {
			return this.page;
		}

		await newPage.waitForLoadState('domcontentloaded');
		return newPage;
	}

