		await expect(this.locator.thoughtsPanel).toContainText(/Searching|Fetching|Retrieved|Reading/i);
	}

	// ============================================================================
	// SQL Response Helper Methods (NL to SQL Tests)
	// ============================================================================

	/**
	 * Waits for SQL code block to appear in response
	 */
	async waitForSQLCodeBlock(timeout: number = 120_000): Promise<void> {
		const responseWidget = this.page.locator('[data-drid*="ai-assistant-message-widget"]').first();
		await responseWidget.waitFor({ state: 'attached', timeout });
		await responseWidget.scrollIntoViewIfNeeded();

		const codeBlock = this.page.locator('pre.rte-code-block').first();
		await codeBlock.waitFor({ state: 'attached', timeout });
		await codeBlock.scrollIntoViewIfNeeded();
		await expect(codeBlock).toBeVisible();
	}

	/**
	 * Expands SQL code block by clicking "Show more" if visible
	 */
	async expandSQLCodeBlock(): Promise<void> {
		const showMoreButton = this.page.getByText('Show more').first();
		// Only click if the button is actually visible
		if (await showMoreButton.isVisible()) {
			await showMoreButton.click();
		}
	}

	/**
	 * Gets SQL code text from the code block
	 */
	async getSQLCode(): Promise<string | null> {
		return await this.page.locator('pre.rte-code-block code').first().textContent();
	}

	/**
	 * Waits for SQL response and returns the SQL code
	 */
	async waitForAndGetSQLCode(timeout: number = 120_000): Promise<string | null> {
		await this.waitForSQLCodeBlock(timeout);
		await this.expandSQLCodeBlock();
		return await this.getSQLCode();
	}

	/**
	 * Validates basic SQL structure (SELECT and FROM keywords)
	 */
	assertBasicSQLStructure(sqlCode: string | null): void {
		expect(sqlCode).toMatch(/SELECT\s+/i);
		expect(sqlCode).toMatch(/FROM\s+/i);
	}

	/**
	 * Validates SQL contains DevRev table references
	 */
	assertSQLContainsDevRevTable(sqlCode: string | null, tables?: string[]): void {
		if (tables && tables.length > 0) {
			const tablePattern = tables.map((t) => `devrev\\.${t}`).join('|');
			expect(sqlCode).toMatch(new RegExp(tablePattern, 'i'));
		} else {
			expect(sqlCode).toMatch(/devrev\.\w+|don:data|dataset/i);
		}
	}

	/**
	 * Validates SQL contains specified columns
	 */
	assertSQLContainsColumns(sqlCode: string | null, columns: string[]): void {
		const columnPattern = columns.join('|');
		expect(sqlCode).toMatch(new RegExp(columnPattern, 'i'));
	}

	/**
	 * Validates SQL contains specific keywords
	 */
	assertSQLContainsKeywords(sqlCode: string | null, keywords: string[]): void {
		for (const keyword of keywords) {
			expect(sqlCode).toMatch(new RegExp(keyword, 'i'));
		}
	}

	/**
	 * Full SQL validation helper - validates structure, tables, and columns
	 */
	assertSQLResponse(
		sqlCode: string | null,
		options: {
			tables?: string[];
			columns?: string[];
			keywords?: string[];
		} = {}
	): void {
		this.assertBasicSQLStructure(sqlCode);
		this.assertSQLContainsDevRevTable(sqlCode, options.tables);

		if (options.columns && options.columns.length > 0) {
			this.assertSQLContainsColumns(sqlCode, options.columns);
		}

		if (options.keywords && options.keywords.length > 0) {
			this.assertSQLContainsKeywords(sqlCode, options.keywords);
		}
	}
}

