 * This modal appears when the feature toggle `experience.ui_quick_create_modal_enabled` is nil/enabled.
 * It supports creating multiple object types: Issue, Ticket, Opportunity, etc.
 */

import { expect, Page } from '@playwright/test';
import { isVisibleWithinTimeout } from '@utils/page.utils';

export class QuickCreateModal {
	constructor(readonly page: Page) {}

	private get dialog() {
		return this.page.getByTestId('quick-create-modal');
	}

	public get locator() {
		return {
			dialog: this.dialog,

			// Text Box
			textBoxTitle: this.dialog.getByTestId('quick-create-entity--title--input--slot-textarea'),
			buttonEditDescription: this.dialog.getByRole('button', { name: 'Edit description' }),

			// Field Buttons (dropdowns are portaled outside the dialog)
			buttonOwner: this.dialog.getByRole('button', { name: 'Owner' }),
			buttonPart: this.dialog.getByRole('button', { name: 'Part' }),

			// Buttons
			buttonCreate: this.dialog.getByTestId('quick-create-entity--submit-button'),

			// Onboarding ("What's Changed") — appears on first use of quick create modal
			onboardingHeading: this.page.getByRole('heading', { name: "What's Changed", level: 1 }),
			buttonOnboardingContinue: this.page.getByRole('button', { name: 'Continue' }),
			buttonOnboardingGetStarted: this.page.getByRole('button', { name: 'Get started' }),
		};
	}

	public async toBeDisplayed(): Promise<void> {
		await expect(this.locator.dialog).toBeVisible();
		await expect(this.locator.textBoxTitle).toBeVisible();
	}

	public async addTitle(title: string): Promise<void> {
		await this.locator.textBoxTitle.fill(title);
	}

	public async addDescription(description: string): Promise<void> {
		await this.locator.buttonEditDescription.click();
		await this.page.keyboard.type(description);
	}

	public async selectOwner(owner: string): Promise<void> {
		await this.locator.buttonOwner.click();
		await this.page.getByRole('menuitemradio', { name: owner }).click();
	}

	public async addPart(partName: string): Promise<void> {
		await this.locator.buttonPart.click();
		// Use last() to skip Suggestions section, consistent with side panel approach
		await this.page.getByRole('menuitem', { name: partName }).last().click();
	}

	/**
	 * Dismisses the "What's Changed" onboarding dialog if it appears before the quick create modal.
	 * Clicks through all "Continue" steps and then "Get started" to reveal the modal.
	 * No-op if the onboarding dialog is not present.
	 */
	public async dismissOnboardingIfPresent(): Promise<void> {
		const { onboardingHeading, buttonOnboardingContinue, buttonOnboardingGetStarted } = this.locator;

		if (!(await isVisibleWithinTimeout(onboardingHeading))) return;

		// Click through all "Continue" steps until "Get started" is shown
		await expect(async () => {
			if (await isVisibleWithinTimeout(buttonOnboardingContinue, 500)) {
				await buttonOnboardingContinue.click();
			}
			await expect(buttonOnboardingGetStarted).toBeVisible({ timeout: 2_000 });
		}).toPass({ timeout: 30_000, intervals: [500, 1000, 2000] });

		await buttonOnboardingGetStarted.click();
	}

	/**
	 * Fill out the modal form with the given data.
	 * Required fields: title, description, owner, part
	 */
	public async fillOutForm(data: { title: string; description: string; owner: string; part: string }): Promise<void> {
		await this.addTitle(data.title);
		await this.addDescription(data.description);
		await this.selectOwner(data.owner);
		await this.addPart(data.part);
	}
}

