		await expect(this.locator.buttonIssueId).toBeVisible();
		await expect(this.locator.buttonIssueId).toHaveText(issueId);
	}

	public async getIssueId(): Promise<string> {
		await expect(this.locator.buttonIssueId).toBeVisible();
		await expect(this.locator.buttonIssueId).toHaveText(/.*ISS-\d+/);

		const issueId = await this.locator.buttonIssueId.textContent();
		if (!issueId) {
			throw new Error('Issue ID not found');
		}
		console.log('Issue ID:', issueId);
		return issueId;
	}

	public async addComment(comment: string): Promise<void> {
		await this.locator.comment.fill(comment);
		await expect(this.locator.buttonSubmitComment).toBeEnabled();
		await this.locator.buttonSubmitComment.click();
	}

	public async assertCommentDisplayed(comment: string): Promise<void> {
		await expect(this.page.locator('div[data-drid*="message--content"]').filter({ hasText: comment })).toBeVisible();
	}

	/**
	 * ================================
	 * Attributes Section
	 * ================================
	 */

	public async selectPriority(priority: 'P0' | 'P1' | 'P2' | 'P3'): Promise<void> {
		await this.locator.attributes.priority.click();
		await this.page.getByRole('menuitemradio', { name: priority }).locator('div').first().click();

		await expect(this.locator.attributes.priority).toHaveText(priority);
	}

	public async selectStage(stage: 'Triage' | 'Backlog' | 'Prioritized' | 'In Development' | 'Completed' | "Won't Fix" | 'Duplicate'): Promise<void> {
		const stageSpinner = this.page.locator('[data-drid="field-form-attributes--field--stage"] [aria-busy="true"]');
		// wait until the spinner disappears
		await stageSpinner.waitFor({ state: 'detached' });
		await this.locator.attributes.stage.click();
		await this.page.getByRole('menuitemradio', { name: stage }).locator('div').first().click();

		await expect(this.locator.attributes.stage).toHaveText(stage);
	}

	public async addTag(tag: string): Promise<void> {
		await this.locator.attributes.tags.click();
		await this.locator.attributes.tagsSelectOptions.waitFor({ state: 'visible' });
		await this.page.locator(`//li[@role="menuitem"][contains(., "${tag}")]`).waitFor({ state: 'visible' });

		await this.locator.attributes.tagsSearch.fill(tag);
		await this.locator.attributes.tagsSearch.press('Enter');
		await this.locator.attributes.tagsSearch.press('Escape'); // close the dropdown menu

		await expect(this.locator.attributes.tags).toHaveText(tag);
	}

	public async updateAttributes(attributes: IssueAttributes): Promise<void> {
		if (attributes.priority) {
			await this.selectPriority(attributes.priority);
		}
		if (attributes.stage) {
			await this.selectStage(attributes.stage);
		}
		if (attributes.tag) {
			await this.addTag(attributes.tag);
		}

		// Implement other attributes updates as needed
	}

	/**
	 * ================================
	 * Action Header Menu Section
	 * ================================
	 */

	public async deleteIssue(issueId: string): Promise<void> {
		const sidePanel = new SidePanel(this.page);
		const deleteModal = new DeleteModal(this.page);

		// Delete the issue flow
		await this.locator.panelHeaderActionMenu.click();
		await this.locator.actionMenu.delete.click();
		await deleteModal.issue.toBeDisplayed();

		await deleteModal.issue.locator.modalTitle.waitFor({ state: 'visible' });
		await expect(deleteModal.issue.locator.modalTitle).toHaveText(`Delete ${issueId}?`);

		await deleteModal.issue.locator.buttonDelete.click();

		// Slide panel will be closed automatically
		await expect(sidePanel.locator.panel).toBeHidden();
	}
}

