/**
 * Validates that orgKey is provided from the project config
 */

function validateOrgKey(orgKey: string, role: string): void {
	if (!orgKey) {
		throw new Error(
			`FAIL FAST: 'orgKey' is missing in the project config. ` +
				`Cannot authenticate as ${role}. ` +
				`Check your playwright.computer.config.ts project definition.`
		);
	}
}

/**
 * Validates that the storage state file exists
 */

function validateStorageFile(filePath: string, org: string, role: string): void {
	if (!fs.existsSync(filePath)) {
		throw new Error(
			`FAIL FAST: Auth state file not found at: ${filePath}\n` +
				`Expected authentication for org="${org}", role="${role}".\n` +
				`Did the setup project run successfully? Run: npx playwright test --config playwright.computer.config.ts --project "setup:${org}:${role}"`
		);
	}
}

