export const test = baseTest.extend<{
	homePage: HomePage;
	loginWithEmailPage: LoginWithEmailPage;
	explorePage: ExplorePage;
	trailsPage: TrailsPage;
	userManagementGroupsPage: UserManagementGroupsPage;
	userManagementRolesPage: UserManagementRolesPage;
	dashboardBuilderPage: DashboardBuilderPage;
}>({
	page: async ({ page }, use) => {
		// Mask navigator.webdriver before any page scripts run.
		// The DevRev app checks this property to detect automation and disables
		// DuckDB-WASM when true, routing to a broken server-side fallback instead.
		// Setting it to undefined restores the normal user code path (DuckDB-WASM).
		await page.addInitScript(() => {
			Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
		});
		await dismissPromotionalBanners(page);
		await use(page);
	},
	homePage: async ({ page }, use) => await use(new HomePage(page)),
	loginWithEmailPage: async ({ page }, use) => await use(new LoginWithEmailPage(page)),
	explorePage: async ({ page }, use) => await use(new ExplorePage(page)),
	trailsPage: async ({ page }, use) => await use(new TrailsPage(page)),
	userManagementGroupsPage: async ({ page }, use) => await use(new UserManagementGroupsPage(page)),
	userManagementRolesPage: async ({ page }, use) => await use(new UserManagementRolesPage(page)),
	dashboardBuilderPage: async ({ page }, use) => await use(new DashboardBuilderPage(page)),
});

