// Dashboard Builder page for creating and configuring widgets

import { Page, expect } from '@playwright/test';

export class DashboardBuilderPage {
	constructor(private readonly page: Page) {}

	public get locator() {
		return {
			nameInput: this.page.getByRole('textbox', { name: /name/i }),
			measuresButton: this.page.getByRole('button', { name: 'Select Measures' }),
			dimensionsButton: this.page.getByRole('button', { name: 'Select Dimensions' }),
			saveButton: this.page.getByRole('button', { name: 'Save' }),
			measuresMenu: this.page.getByRole('menu', { name: 'Select Measures' }),
		};
	}

	async assertBuilderDisplayed(): Promise<void> {
		await expect(this.page.getByText('Name', { exact: true })).toBeVisible();
		await expect(this.page.getByText('Measures', { exact: true })).toBeVisible();
		await expect(this.page.getByText('Dimensions', { exact: true })).toBeVisible();
		await expect(this.page.getByText('Visualization', { exact: true })).toBeVisible();
		await expect(this.locator.saveButton).toBeVisible();
	}

	async setWidgetName(name: string): Promise<void> {
		await this.locator.nameInput.clear();
		await this.locator.nameInput.fill(name);
	}

	async selectMeasure(measureName: string): Promise<void> {
		await this.locator.measuresButton.click();
		await expect(this.locator.measuresMenu).toBeVisible();
		await this.page.getByRole('menuitemcheckbox', { name: measureName }).click();
		await this.page.keyboard.press('Escape');
	}

	async saveWidget(): Promise<void> {
		await this.locator.saveButton.click();
	}

	async createWidget(config: WidgetConfig): Promise<void> {
		await this.setWidgetName(config.name);
		await this.selectMeasure(config.measure);
		// TODO: Add support for optional fields when needed:
		// if (config.dimension) await this.selectDimension(config.dimension);
		// if (config.visualizationType) await this.selectVisualizationType(config.visualizationType);
		await this.saveWidget();
	}
}

