	/**
	 * Sends a message in the computer chat.
	 * Uses expect.toPass() to handle intermittent failures.
	 * Clears input on retry to ensure clean state.
	 */
	async sendMessage(message: string): Promise<void> {
		// Wait for input to be ready and click to focus
		await expect(this.locator.computerInputTextBox).toBeVisible({ timeout: 30_000 });
		await this.locator.computerInputTextBox.click();

		await expect(async () => {
			// Clear input first to handle retry scenarios
			await this.locator.computerInputTextBox.clear();
			await this.locator.computerInputTextBox.pressSequentially(message);
			// wait for send button to be enabled
			await expect(this.locator.buttonSendMessage).toBeEnabled({ timeout: 5_000 });
			await this.locator.buttonSendMessage.click();
			// Verify message was sent by checking it appears in the chat
			const sentMessage = this.locator.messageEditor.filter({ hasText: message }).first();
			await expect(sentMessage).toBeVisible({ timeout: 15_000 });
		}).toPass({ timeout: 60_000 });
	}

