	/**
	 * Copies the agent response to clipboard and verifies by pasting.
	 * Uses paste verification since clipboard readText() is unreliable on Mac headless.
	 * Compares the pasted content with the original agent response.
	 */
	async assertAgentResponseCopiedToClipboard(): Promise<void> {
		// Get the agent response text before copying
		const agentResponse = await this.locator.agentResponseMessage.last().textContent();
		expect(agentResponse?.trim()).toBeTruthy();
		const expectedSubstring = agentResponse?.trim().substring(0, 50) ?? '';

		await expect(this.locator.feedbackButtons.copy).toBeVisible();

		const modifier = process.platform === 'darwin' ? 'Meta' : 'Control';

		// Retry copy-paste verification to handle clipboard timing issues
		await expect(async () => {
			// Clear input first
			await this.locator.computerInputTextBox.focus();
			await this.page.keyboard.press(`${modifier}+KeyA`);
			await this.page.keyboard.press('Backspace');

			// Click copy button
			await this.locator.feedbackButtons.copy.click();

			// Focus input and paste
			await this.locator.computerInputTextBox.focus();
			await this.page.keyboard.press(`${modifier}+KeyV`);

			// Verify pasted content
			const pastedContent = await this.locator.computerInputTextBox.textContent();
			expect(pastedContent?.trim()).toContain(expectedSubstring);
		}).toPass({ timeout: 50_000, intervals: [1000, 2000, 5000] });

		// Clean up: clear the input
		await this.locator.computerInputTextBox.focus();
		await this.page.keyboard.press(`${modifier}+KeyA`);
		await this.page.keyboard.press('Backspace');
	}

