	/**
	 * Toggles the unread notifications switch to the desired state.
	 * Checks current state first and only clicks if needed.
	 * Uses expect.toPass() to handle cases where the panel may be closed by UI interference.
	 */
	async toggleUnreadNotificationsSwitch(state: 'ON' | 'OFF'): Promise<void> {
		await expect(async () => {
			// Ensure panel is visible before toggling
			if (!(await isVisibleWithinTimeout(this.locator.notificationPanel.container, 1_000))) {
				await this.openNotificationPanel();
			}

			const isEnabled = await this.locator.notificationPanel.unreadToggle.isChecked();
			const desired = state === 'ON';
			if (isEnabled !== desired) {
				await this.locator.notificationPanel.unreadToggle.click();
			}
			await expect(this.locator.notificationPanel.unreadToggle).toBeChecked({ checked: desired });
		}).toPass({ timeout: 60_000 });
	}

