	async assertFeedbackDropdownOptionsAvailable(): Promise<void> {
		const expectedOptions = ['Incorrect answer', 'Incomplete response', 'Too lengthy', 'Outdated information', 'No answer offered', 'Other'];

		// Verify count matches expected
		await expect.soft(this.page.getByRole('menuitemradio')).toHaveCount(expectedOptions.length);

		// Verify each option is available
		for (const option of expectedOptions) {
			await expect.soft(this.page.getByRole('menuitemradio', { name: option })).toBeVisible();
		}
	}

	/**
	 * Opens the feedback reason dropdown and asserts options are visible.
	 * Uses expect.toPass() to retry the click if the dropdown is flaky to open.
	 */
	async openFeedbackReasonDropdown(): Promise<void> {
		await expect(async () => {
			// Try clicking the trigger
			await this.locator.feedbackDialog.selectReasonTrigger.click();

			// Hard assertion: Check if at least one option becomes visible.
			// This is required because assertFeedbackDropdownOptionsAvailable() uses expect.soft().
			// Without a hard assertion, a failure wouldn't trigger the toPass retry loop.
			await expect(this.page.getByRole('menuitemradio').first()).toBeVisible({ timeout: 1000 });

			// Verify all options are correctly populated
			await this.assertFeedbackDropdownOptionsAvailable();
		}).toPass({
			timeout: 15_000,
			intervals: [500, 1000, 2000],
		});
	}

	/**
	 * Selects a reason from the feedback dropdown.
	 * Checks if dropdown is open via the first option (always in view), then scrolls to the target option.
	 */
	async selectFeedbackReason(
		reason: 'Incorrect answer' | 'Incomplete response' | 'Too lengthy' | 'Outdated information' | 'No answer offered' | 'Other'
	): Promise<void> {
		const optionLocator = this.page.getByRole('menuitemradio', { name: reason });

		await expect(async () => {
			// Check if dropdown is open using the first option (always visible when open)
			if (!(await isVisibleWithinTimeout(this.page.getByRole('menuitemradio').first(), 1_000))) {
				await this.locator.feedbackDialog.selectReasonTrigger.click({ timeout: 2000 });
				await expect(this.page.getByRole('menuitemradio').first()).toBeVisible({ timeout: 2000 });
			}

			// Scroll to the target option (e.g. "Other" may be below the fold)
			await optionLocator.scrollIntoViewIfNeeded();
			await optionLocator.click({ timeout: 2000 });

