	}

	/**
	 * Assert article details on the opened article page (title, product, status, scope)
	 */
	async assertArticleDetails(articlePage: Page, options: { title: string; productName: string }): Promise<void> {
		const { title, productName } = options;
		await expect(articlePage.getByTestId('articles--field--title').filter({ hasText: title })).toBeVisible();
		await expect(articlePage.getByTestId('articles--field--appliesToParts-value').filter({ hasText: productName })).toBeVisible();
		await expect(
			articlePage
				.getByTestId('articles--field--status-value_status')
				.or(articlePage.getByTestId('articles--field--status_status'))
				.filter({ hasText: 'Published' })
		).toBeVisible();
		await expect(articlePage.getByTestId('articles--field--scope_scope').filter({ hasText: 'External' })).toBeVisible();
	}

	/**
	 * Assert response contains specific text
	 */
	async assertResponseContainsText(text: string): Promise<void> {
		await expect(this.locator.textContent(text)).toBeVisible();
	}

	/**
	 * Assert response indicates no article was found (handles AI response variations)
	 */
	async assertNoArticleFoundResponse(): Promise<void> {
		// AI responses can vary, so check for common patterns including error states
		const noArticlePatterns =
			/didn't find|couldn't find|could not find|unable to find|wasn't able to find|no article|not found|don't have|unable to process|try again|no relevant|no information|no results/i;
		await expect(this.page.locator('body')).toContainText(noArticlePatterns);
	}

	// =====================================================
	// Thoughts Helper Methods
	// =====================================================

	/**
	 * Expands the Thoughts panel with retry logic.
	 * The thoughts bubble click may not always expand on first attempt.
	 */
	async expandThoughtsPanel(): Promise<void> {
		await expect(this.locator.buttonThoughts).toBeVisible({ timeout: 60_000 });
		await expect(async () => {
			await this.locator.buttonThoughts.click();
			await expect(this.locator.thoughtsPanel).toBeVisible({ timeout: 1_000 });
		}).toPass({ timeout: 15_000, intervals: [1_000, 2_000, 3_000] });
		await expect(this.locator.thoughtsPanel).toContainText(/Searching|Fetching|Retrieved|Reading/i);
	}

	// =====================================================
	// SQL Response Helper Methods (NL to SQL Tests)
	// =====================================================

	/**
	 * Waits for SQL code block to appear in response
	 * First waits for response widget, then for code block
	 * @param timeout - Timeout for waiting (default 120s)
	 */
	async waitForSQLCodeBlock(timeout: number = 120_000): Promise<void> {
		// Wait for response widget first (more reliable)
		await this.locator.responseWidget.waitFor({ state: 'attached', timeout });
		await this.locator.responseWidget.scrollIntoViewIfNeeded();

		// Then wait for code block with same timeout (AI may take time to generate SQL)
		await this.locator.sqlCodeBlock.waitFor({ state: 'attached', timeout });
		await this.locator.sqlCodeBlock.scrollIntoViewIfNeeded();
		await expect(this.locator.sqlCodeBlock).toBeVisible();
	}

	/**
	 * Expands SQL code block by clicking "Show more" if visible
	 */
	async expandSQLCodeBlock(): Promise<void> {
		// Only click if the button is actually visible
		if (await isVisibleWithinTimeout(this.locator.buttonShowMore, 1_000)) {
			await this.locator.buttonShowMore.click();
		}
	}

	/**
	 * Gets SQL code text from the code block
	 * @returns SQL code as string or null
	 */
	async getSQLCode(): Promise<string | null> {
		return await this.locator.sqlCodeContent.textContent();
	}

	/**
	 * Waits for SQL response and returns the SQL code
	 * Combines: wait for code block + expand + get code
	 * @param timeout - Timeout for waiting (default 120s)
	 * @returns SQL code as string or null
	 */
	async waitForAndGetSQLCode(timeout: number = 120_000): Promise<string | null> {
		await this.waitForSQLCodeBlock(timeout);
		await this.expandSQLCodeBlock();
		return await this.getSQLCode();
	}

	/**
	 * Validates basic SQL structure (SELECT and FROM keywords)
	 * @param sqlCode - SQL code to validate
	 */
	assertBasicSQLStructure(sqlCode: string | null): void {
		expect(sqlCode).toMatch(/SELECT\s+/i);
		expect(sqlCode).toMatch(/FROM\s+/i);
	}

	/**
	 * Validates SQL contains DevRev table references
	 * @param sqlCode - SQL code to validate
	 * @param tables - Specific tables to check (default: any devrev table or DON reference)
	 */
	assertSQLContainsDevRevTable(sqlCode: string | null, tables?: string[]): void {
		if (tables && tables.length > 0) {
			// Check for specific tables
			const tablePattern = tables.map((t) => `devrev\\.${t}`).join('|');
			expect(sqlCode).toMatch(new RegExp(tablePattern, 'i'));
		} else {
			// Check for any devrev table or DON dataset reference
			expect(sqlCode).toMatch(/devrev\.\w+|don:data|dataset/i);
		}
	}

	/**
	 * Validates SQL contains specified columns
	 * @param sqlCode - SQL code to validate
	 * @param columns - Array of column names to check
	 */
	assertSQLContainsColumns(sqlCode: string | null, columns: string[]): void {
		const columnPattern = columns.join('|');
		expect(sqlCode).toMatch(new RegExp(columnPattern, 'i'));
	}

	/**
	 * Validates SQL contains specific keywords
	 * @param sqlCode - SQL code to validate
	 * @param keywords - Array of SQL keywords to check (e.g., 'JOIN', 'WHERE', 'ORDER BY')
	 */
	assertSQLContainsKeywords(sqlCode: string | null, keywords: string[]): void {
		for (const keyword of keywords) {
			expect(sqlCode).toMatch(new RegExp(keyword, 'i'));
		}
	}

	/**
	 * Full SQL validation helper - validates structure, tables, and columns
	 * @param sqlCode - SQL code to validate
	 * @param options - Validation options
	 */
	assertSQLResponse(
		sqlCode: string | null,
		options: {
			tables?: string[];
			columns?: string[];
			keywords?: string[];
		} = {}
	): void {
		// Always validate basic structure
		this.assertBasicSQLStructure(sqlCode);

		// Validate tables if specified
		this.assertSQLContainsDevRevTable(sqlCode, options.tables);

		// Validate columns if specified
		if (options.columns && options.columns.length > 0) {
			this.assertSQLContainsColumns(sqlCode, options.columns);
		}

		// Validate additional keywords if specified
		if (options.keywords && options.keywords.length > 0) {
			this.assertSQLContainsKeywords(sqlCode, options.keywords);
		}
	}
}

