	async assertWebSearchToolRemoved(): Promise<void> {
		await expect(this.locator.gridcellWebSearch).toBeHidden();
		await expect(this.locator.buttonEnableWebSearch).toBeVisible();
	}

	/**
	 * Removes WebSearch capability if it exists from a previous test run.
	 * Used to ensure a clean state before page structure assertions.
	 * Waits for the capabilities section to finish loading before checking,
	 * to avoid a race condition where isVisible() runs before the table renders.
	 */
	async removeWebSearchIfPresent(): Promise<void> {
		// Wait for the page to settle by waiting for either the WebSearch row or the empty state,
		// which are the two possible stable states after the capabilities table loads
		const webSearchRow = this.locator.rowWebSearch;
		const emptyState = this.locator.textEmptyCapabilities;

		await expect(webSearchRow.or(emptyState).first()).toBeVisible({ timeout: 30_000 });

		if (await webSearchRow.isVisible()) {
			await this.removeWebSearchTool();
			await this.assertWebSearchToolRemoved();
		}
	}
}

