	/**
	 * Opens the actions menu (burger menu) for a specific user row.
	 * Uses expect.toPass to handle flaky menu opening - the menu button click sometimes
	 * doesn't register on first attempt, especially when the table is still rendering.
	 */
	async openUserActionsMenu(email: string): Promise<void> {
		const row = this.getUserRowByEmail(email);
		const menuButton = row.locator('button[data-drid*="users_settings_action_cell"]');

		await expect(async () => {
			await menuButton.click();
			// Verify menu is actually open by checking for a menu item
			await expect(this.locator.menuItemDeactivateUser.or(this.locator.menuItemActivateUser).first()).toBeVisible({ timeout: 5_000 });
		}).toPass({
			timeout: 30_000,
			intervals: [1_000, 2_000, 3_000],
		});
	}

	private async waitForUsersToLoad(): Promise<void> {
		// Wait for any row containing a gridcell (data rows have gridcells, header rows have columnheaders)
		await this.locator.treegridUsers
			.locator('div[role="row"]')
			.filter({ has: this.page.locator('[role="gridcell"]') })
			.first()
			.waitFor({ state: 'visible', timeout: 60000 });
	}

	/**
	 * Removes the User State filter by hovering and clicking its close button.
	 * Uses expect.toPass to handle timing issues - the filter close button only appears
	 * on hover and may not register clicks immediately. The filter also takes time to
	 * disappear after clicking, and the table needs to refresh with new data.
	 */
	async clearUserStateFilter(): Promise<void> {
		await expect(async () => {
			// Wait for filter to be visible
			const filterVisible = await this.locator.filterUserState
				.waitFor({ state: 'visible', timeout: 30_000 })
				.then(() => true)
				.catch(() => false);

			if (filterVisible) {
				await this.locator.filterUserState.hover();
				await this.locator.buttonRemoveUserStateFilter.click();
			}

			// Verify filter is actually removed
			await expect(this.locator.filterUserState).not.toBeVisible({ timeout: 5_000 });
		}).toPass({
			timeout: 60_000,
			intervals: [1_000, 2_000, 3_000],
		});
	}

