		// This order is more reliable as the toast appears when the backend confirms the action.
		await expect(this.page.getByRole('alert').filter({ hasText: 'User deactivated successfully' })).toBeVisible();
		await expect(this.locator.dialogDeactivateUser).not.toBeVisible();
	}

	async activateUser(email: string): Promise<void> {
		await this.openUserActionsMenu(email);
