	 * Asserts that a user is in a deactivated state by checking the actions menu.
	 * Deactivated users show "Activate user" option in their menu.
	 */
	async assertUserIsDeactivated(email: string): Promise<void> {
		await this.openUserActionsMenu(email);
		await expect(this.locator.menuItemActivateUser).toBeVisible();
		await this.page.keyboard.press('Escape');
	}

	/**
	 * Asserts that a user is in an active state by checking the actions menu.
	 * Active users show "Deactivate user" option in their menu.
	 */
	async assertUserIsActive(email: string): Promise<void> {
		await this.openUserActionsMenu(email);
		await expect(this.locator.menuItemDeactivateUser).toBeVisible();
		await this.page.keyboard.press('Escape');
	}

	/**
	 * Checks if a user is currently deactivated by examining the actions menu.
	 * returns true if user is deactivated, false if active
	 */
	async isUserDeactivated(email: string): Promise<boolean> {
		await this.openUserActionsMenu(email);
		const isDeactivated = await this.locator.menuItemActivateUser
			.waitFor({ state: 'visible', timeout: 5_000 })
			.then(() => true)
			.catch(() => false);
		await this.page.keyboard.press('Escape');
		return isDeactivated;
	}

	/**
	 * Ensures a user is in active state, activating them if necessary.
	 * Used to set up test prerequisites (e.g., ensure user is active before testing deactivation).
	 */
	async ensureUserIsActive(email: string): Promise<void> {
		const isDeactivated = await this.isUserDeactivated(email);
		if (isDeactivated) {
			await this.activateUser(email);
		}
	}

	async assertDeactivateUserMenuItemDisabled(email: string): Promise<void> {
		await this.openUserActionsMenu(email);
		await expect(this.locator.menuItemDeactivateUser).toBeVisible();
		await expect(this.locator.menuItemDeactivateUser).toHaveAttribute('aria-disabled', 'true');
		await this.page.keyboard.press('Escape');
	}

	// ============================================================================
	// USER ROLE MANAGEMENT
	// ============================================================================

	/**
	 * Gets the role button for a specific user row.
	 * Admin/Billing Admin see a clickable button, Members see plain text.
	 */
	getUserRoleButton(email: string) {
		const row = this.getUserRowByEmail(email);
		return row.getByRole('button', { name: /Admin|Member/ });
	}

	/**
	 * Gets the current role of a user by reading the role cell text.
	 * returns 'Admin' or 'Member'
	 */
	async getUserRole(email: string): Promise<'Admin' | 'Member'> {
		const row = this.getUserRowByEmail(email);
		await expect(row).toBeVisible({ timeout: 60_000 });

		const ROLE_CHECK_TIMEOUT = 2_000;

		const isAdmin = await row
			.getByRole('gridcell', { name: 'Admin' })
			.waitFor({ state: 'visible', timeout: ROLE_CHECK_TIMEOUT })
			.then(() => true)
			.catch(() => false);
		return isAdmin ? 'Admin' : 'Member';
	}

	async changeUserRole(email: string, newRole: 'Admin' | 'Member'): Promise<void> {
		const roleButton = this.getUserRoleButton(email);

		// Use expect.toPass to handle flaky button clicks
		await expect(async () => {
			await roleButton.click();
			// Verify menu opened by checking if role options are visible
			await expect(this.locator.menuItemRadioAdmin.or(this.locator.menuItemRadioMember).first()).toBeVisible({ timeout: 5_000 });
		}).toPass({
			timeout: 30_000,
			intervals: [1_000, 2_000, 3_000],
		});

		// Select the new role
		if (newRole === 'Admin') {
			await this.locator.menuItemRadioAdmin.click();
		} else {
			await this.locator.menuItemRadioMember.click();
		}
	}

	async assertUserHasRole(email: string, expectedRole: 'Admin' | 'Member'): Promise<void> {
		const row = this.getUserRowByEmail(email);
		await expect(row).toBeVisible({ timeout: 60_000 });
		await expect(row.getByRole('gridcell', { name: expectedRole })).toBeVisible();
	}

	/**
	 * Ensures a user has a specific role, changing it if necessary.
	 * Used to set up test prerequisites (e.g., ensure user is Member before testing role change).
	 */
	async ensureUserRole(email: string, desiredRole: 'Admin' | 'Member'): Promise<void> {
		const currentRole = await this.getUserRole(email);
		if (currentRole !== desiredRole) {
			await this.changeUserRole(email, desiredRole);
			await this.assertUserHasRole(email, desiredRole);
		}
	}

	/**
	 * Asserts that the role selector is not clickable (for Members viewing other users).
	 * Members see plain text instead of a button.
	 */
	async assertRoleIsNotEditable(email: string): Promise<void> {
		const row = this.getUserRowByEmail(email);
		await expect(row).toBeVisible({ timeout: 60_000 });
		// Members see gridcell without a button
		const roleButton = row.getByRole('button', { name: /Admin|Member/ });
		await expect(roleButton).toHaveCount(0);
	}
}

