import { expect, Locator, Page } from '@playwright/test';
import { FeatureToggleValue } from '@config/featureToggles.registry';

export class FeatureTogglesSection {
	constructor(private readonly page: Page) {}

	private escapeRegExp(value: string): string {
		return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
	}

	private toSubmitValue(value: FeatureToggleValue): string {
		return value === '<nil>' ? '' : value;
	}

	private get featureTogglesFrame() {
		return this.page.frameLocator('iframe[title="Feature Toggles"]');
	}

	private getToggleRow(toggleName: string): Locator {
		return this.featureTogglesFrame.getByRole('row', {
			name: new RegExp(this.escapeRegExp(toggleName)),
		});
	}

	public get locator() {
		return {
			iframeFeatureToggles: this.featureTogglesFrame.owner(),
			textSuccessMessage: this.featureTogglesFrame.getByText(/^success$/),
		};
	}

	public async assertToggleVisible(toggleName: string): Promise<void> {
		await expect(this.getToggleRow(toggleName)).toBeVisible();
	}

	public async getToggleCurrentValue(toggleName: string): Promise<FeatureToggleValue> {
		const valueInput = this.getToggleRow(toggleName).getByRole('textbox');
		await expect(valueInput).toBeVisible();
		const rawValue = await valueInput.inputValue();
		return (rawValue === '' ? '<nil>' : rawValue) as FeatureToggleValue;
	}

	public async setToggleValue(toggleName: string, value: FeatureToggleValue): Promise<void> {
		const toggleRow = this.getToggleRow(toggleName);
		const valueInput = toggleRow.getByRole('textbox');
		const buttonSubmit = toggleRow.getByRole('button', { name: 'Submit' });

		await valueInput.fill(this.toSubmitValue(value));
		await buttonSubmit.click();
		await expect(this.locator.textSuccessMessage).toBeVisible();

		// Reload the page to ensure the new value is reflected in the table
		await this.page.reload({ waitUntil: 'domcontentloaded' });
		await expect(this.locator.iframeFeatureToggles).toBeVisible();
		await expect.poll(async () => this.getToggleCurrentValue(toggleName)).toBe(value);
	}
}

