import { Page, expect } from '@playwright/test';
import { LoginWithEmailPage } from '@pages/login.page';
import { readOtpFromGmail } from './email.utils';

const ERROR_SOMETHING_WENT_WRONG = "WE'RE SORRY, SOMETHING WENT WRONG";

const ERROR_ACCOUNT_BLOCKED = 'YOUR ACCOUNT HAS BEEN BLOCKED';

/**
 * Complete OTP-based login flow with retry logic.
 * Critical for auth setup - uses expect.toPass to handle flaky OTP scenarios.
 * Limited to 2 retries with 10s/15s intervals to avoid triggering account lockout.
 */

export async function loginWithOtp(page: Page, options: { email: string; org: string; role: string }): Promise<void> {
	const loginPage = new LoginWithEmailPage(page);
	const { email, role } = options;

	let accountBlocked = false;

	await expect(async () => {
		// Fail fast if account was blocked in previous attempt
		if (accountBlocked) {
			throw new Error('FATAL: Account blocked due to multiple login attempts. Manual intervention required.');
		}

		// Fill email and request OTP
		await loginPage.fillEmail(email);
		const otpRequestedAt = new Date();
		await loginPage.clickSubmit();
		await loginPage.assertOtpInputVisible();

		const otp = await pollForOtp(email, role, otpRequestedAt);
		await loginPage.fillOtp(otp);

		await loginPage.clickSubmit();

		// Check for errors - sets flag if blocked
		await verifyNoLoginErrors(page, () => {
			accountBlocked = true;
		});
	}).toPass({
		timeout: 60_000,
		intervals: [10_000, 15_000],
	});
}

/**
 * Checks for login errors after OTP submission.
 * - BLOCKED: Sets flag via callback so next retry fails immediately
 * - SOMETHING WENT WRONG: Clicks resend and throws to trigger retry
 */

import { Page, expect } from '@playwright/test';
import { LoginWithEmailPage } from '@pages/login.page';
import { readOtpFromGmail } from './email.utils';

async function verifyNoLoginErrors(page: Page, onBlocked: () => void): Promise<void> {
	// Check for account blocked FIRST - this is fatal
	const blockedBanner = page.getByText(ERROR_ACCOUNT_BLOCKED);
	const isBlocked = await blockedBanner
		.waitFor({ state: 'visible', timeout: 2_000 })
		.then(() => true)
		.catch(() => false);

	if (isBlocked) {
		onBlocked();
		throw new Error('Account blocked detected');
	}

	// Check for "something went wrong" - this is retryable
	const errorBanner = page.getByText(ERROR_SOMETHING_WENT_WRONG);
	const hasError = await errorBanner
		.waitFor({ state: 'visible', timeout: 2_000 })
		.then(() => true)
		.catch(() => false);

	if (hasError) {
		console.warn('OTP failed - clicking "Did not get the code?" for retry');
		await page.getByText('Did not get the code?').click();
		throw new Error('OTP validation failed - retrying');
	}
}


async function pollForOtp(
	email: string,
	role: string,
	otpRequestedAt: Date,
	timeoutMs: number = 60_000,
	intervalMs: number = 5_000
): Promise<string> {
	const startTime = Date.now();
	console.log(`Polling for OTP sent after ${otpRequestedAt.toISOString()}...`);

	while (Date.now() - startTime < timeoutMs) {
		try {
			const otp = await readOtpFromGmail(email, role, otpRequestedAt);
			if (otp) {
				console.log(`Found fresh OTP (requested at ${otpRequestedAt.toISOString()})`);
				return otp;
			}
			console.log('Fresh OTP not found yet, retrying...');
		} catch (error) {
			console.warn('Error fetching OTP:', error);
		}
		await new Promise((resolve) => setTimeout(resolve, intervalMs));
	}

	throw new Error(`Failed to retrieve OTP after ${timeoutMs / 1000}s`);
}

import fs from 'fs';
