import yaml from 'js-yaml';

type UserData = {
	email: string;
	'full-name': string;
	'display-name': string;
};


type UsersYaml = Record<
	string, // org
	Record<
		string, // role
		{
			users: UserData[];
		}
	>
>;


function loadComputerUsers(): UsersYaml {
	const filePath = path.resolve(__dirname, '../../test-data/computer/users.yaml');

	try {
		const contents = fs.readFileSync(filePath, 'utf-8');
		return yaml.load(contents) as UsersYaml;
	} catch (error) {
		throw new Error(`Could not load Computer users YAML: ${error}`);
	}
}

// Get Computer test user email for a given org and role

export function getComputerUserEmail(org: string, role: string): string {
	const users = loadComputerUsers();

	const roleData = users[org]?.[role];

	if (!roleData?.users || roleData.users.length === 0) {
		throw new Error(`No users configured for org=${org}, role=${role}`);
	}

	const user = roleData.users[0];

	if (!user?.email) {
		throw new Error(`Email is undefined for org=${org}, role=${role}`);
	}

	return user.email;
}

// Get Computer test user data (email, full name, display name) for a given org and role

export function getComputerUserData(org: string, role: string, userIndex = 0): UserData {
	const users = loadComputerUsers();

	const roleData = users[org]?.[role];

	if (!roleData?.users || roleData.users.length === 0) {
		throw new Error(`No users configured for org=${org}, role=${role}`);
	}

	const user = roleData.users[userIndex];

	if (!user) {
		throw new Error(`User at index ${userIndex} is undefined for org=${org}, role=${role}`);
	}

	return user;
}

