// FEATURE FLAGS LOADING
// ============================================================================

const computerFeatureFlags = loadComputerFeatureFlags();

function loadComputerFeatureFlags(): ComputerFeatureFlagsYaml {
	const filePath = path.resolve(__dirname, '../config/feature-flags/computer-features.yaml');
	try {
		const contents = fs.readFileSync(filePath, 'utf-8');
		return yaml.load(contents) as ComputerFeatureFlagsYaml;
	} catch (error) {
		throw new Error(`Could not load Computer features YAML: ${error}`);
	}
}

/**
 * Checks if a Computer feature is enabled for the current environment and org type.
 * Throws an error if the feature is not defined in the YAML (fail fast).
 */
export function hasComputerFeature(feature: string, orgType: ComputerOrgType): boolean {
	const env = ENV.TEST_ENV;

	if (!computerFeatureFlags[env]) {
		throw new Error(`Computer feature flags not defined for environment: ${env}`);
	}

	if (!computerFeatureFlags[env][orgType]) {
		throw new Error(`Computer feature flags not defined for org type: ${orgType} in environment: ${env}`);
	}

	if (computerFeatureFlags[env][orgType][feature] === undefined) {
		throw new Error(`Computer feature "${feature}" not defined for ${env}/${orgType} in computer-features.yaml`);
	}

	return computerFeatureFlags[env][orgType][feature];
}

import { Page, Response } from '@playwright/test';
import { extractRegionFromConfig } from '@utils/region.utils';

export class AppConfigObserver {
	private appVersion: string = 'unknown';
	private plugVersion: string = 'unknown';
	private region: string = 'unknown';
	private appConfigCaptured = false;
	private plugConfigCaptured = false;
	private configCapturedPromise: Promise<void>;
	private resolveConfigCaptured: () => void = () => {};
	private responseHandler: (response: Response) => Promise<void>;

	constructor(private page: Page) {
		this.configCapturedPromise = new Promise((resolve) => {
			this.resolveConfigCaptured = resolve;
		});

		this.responseHandler = async (response: Response) => {
			const url = response.url();
			const isPlugConfig = url.includes('/plug-config');
			const isAppConfig = !isPlugConfig && url.includes('/config');

			if ((!isAppConfig && !isPlugConfig) || !response.ok()) return;

			try {
				const json = await response.json();

				if (isAppConfig && json.APP_VERSION) {
					this.appVersion = json.APP_VERSION;
					this.appConfigCaptured = true;

					const detectedRegion = extractRegionFromConfig(json);
					if (detectedRegion && detectedRegion !== 'unknown') {
						this.region = detectedRegion;
					}
				}

				if (isPlugConfig && json.APP_VERSION) {
					this.plugVersion = json.APP_VERSION;
					this.plugConfigCaptured = true;
				}

				if (this.appConfigCaptured && this.plugConfigCaptured) {
					this.resolveConfigCaptured();
				}
			} catch (error) {
				console.warn(`Failed to parse config response from ${url}:`, error);
			}
		};
	}

	start() {
		this.page.on('response', this.responseHandler);
	}

	stop() {
		this.page.off('response', this.responseHandler);
	}

	async getResult(timeout = 5000): Promise<{ appVersion: string; plugVersion: string; region: string }> {
		const timeoutPromise = new Promise<void>((resolve) => setTimeout(resolve, timeout));
		await Promise.race([this.configCapturedPromise, timeoutPromise]);

		return {
			appVersion: this.appVersion,
			plugVersion: this.plugVersion,
			region: this.region,
		};
	}
}

