interface OtpCandidate {
	otp: string;
	timestamp: Date;
}


interface InvitationCandidate {
	link: string;
	timestamp: Date;
	orgName: string;
}


interface ImapConfig {
	lookbackMinutes: number;
	fromContains: string;
	subjectContains: string;
	timeoutMs: number;
	freshnessBufferMs: number;
}


interface InvitationImapConfig {
	lookbackMinutes: number;
	fromContains: string;
	subjectContains: string;
	timeoutMs: number;
	freshnessBufferMs?: number;
}


interface ImapMessage {
	on: (event: string, callback: (stream: NodeJS.ReadableStream) => void) => void;
}


interface ImapFetch {
	on: (event: string, callback: (msg: ImapMessage) => void) => void;
	once: (event: string, callback: (err?: Error) => void) => void;
}

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

interface ImapConnection {
	openBox: (boxName: string, readOnly: boolean, callback: (err: Error | null) => void) => void;
	search: (criteria: unknown[], callback: (err: Error | null, results: number[]) => void) => void;
	fetch: (source: number[], options: { bodies: string; markSeen: boolean }) => ImapFetch;
	once: (event: string, callback: (err?: Error) => void) => void;
	connect: () => void;
	end: () => void;
	state?: string;
}

// Extract OTP code from email text using various patterns

function extractOtpFromText(text: string): string | null {
	const patterns = [
		/Your code is: (\d{6})/,
		/(\d{6})(?= is your authentication code)/,
		/code[:\s]*(\d{6})/i,
		/verification[:\s]*(\d{6})/i,
		/(\d{6})/, // Fallback: simple 6-digit pattern
	];

	for (const pattern of patterns) {
		const match = text.match(pattern);
		if (match?.[1]) return match[1];
	}

	return null;
}

// Validate if email matches OTP criteria

function isValidOtpEmail(fromText: string, subject: string, config: ImapConfig): boolean {
	const fromLower = fromText.toLowerCase();
	const subjectLower = subject.toLowerCase();

	return fromLower.includes(config.fromContains.toLowerCase()) && subjectLower.includes(config.subjectContains.toLowerCase());
}

// Get configuration with environment variable overrides

function getOtpConfig(): ImapConfig {
	const envTimeout = parseInt(process.env.OTP_TIMEOUT_MS ?? '');
	const timeoutMs = !isNaN(envTimeout) ? envTimeout : OTP_CONFIG.timeoutMs;

	return {
		lookbackMinutes: parseInt(process.env.OTP_LOOKBACK_MINUTES ?? '') || OTP_CONFIG.lookbackMinutes,
		fromContains: OTP_CONFIG.fromContains,
		subjectContains: process.env.OTP_SUBJECT_CONTAINS ?? OTP_CONFIG.subjectContains,
		timeoutMs,
		freshnessBufferMs: OTP_CONFIG.freshnessBufferMs,
	};
}

// Process a single email message and extract OTP if valid

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

async function processEmailMessage(raw: string, config: ImapConfig): Promise<OtpCandidate | null> {
	try {
		const parsed = await simpleParser(raw);

		const fromText = parsed.from?.text || '';
		const subject = parsed.subject || '';
		const text = parsed.text || '';
		const date = parsed.date ? new Date(parsed.date) : new Date();

		// Guard: Check if email matches criteria
		if (!isValidOtpEmail(fromText, subject, config)) {
			return null;
		}

		// Guard: Extract OTP
		const otp = extractOtpFromText(text);
		if (!otp) return null;

		return { otp, timestamp: date };
	} catch {
		// Silently ignore parse errors
		return null;
	}
}

// Fetch and process all emails, returning OTP candidates

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

function fetchAndProcessEmails(imap: ImapConnection, results: number[], config: ImapConfig): Promise<OtpCandidate[]> {
	return new Promise((resolve, reject) => {
		const fetch = imap.fetch(results, { bodies: '', markSeen: true });
		const candidates: OtpCandidate[] = [];
		let processedCount = 0;

		const checkCompletion = () => {
			processedCount++;
			if (processedCount === results.length) {
				resolve(candidates);
			}
		};

		fetch.on('message', (msg: ImapMessage) => {
			let raw = '';

			msg.on('error', () => {
				checkCompletion();
			});

			msg.on('body', (stream: NodeJS.ReadableStream) => {
				stream.on('data', (chunk: Buffer) => {
					raw += chunk.toString('utf8');
				});

				stream.once('end', async () => {
					const candidate = await processEmailMessage(raw, config);
					if (candidate) candidates.push(candidate);
					checkCompletion();
				});

				stream.once('error', () => {
					checkCompletion();
				});
			});
		});

		fetch.once('error', reject);
		fetch.once('end', () => {
			// All messages fetched, processing continues in stream.end
		});
	});
}

// Search for emails and return most recent OTP
// minTimestamp: Only accept OTPs from emails sent after this timestamp (used to filter stale OTPs)

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

function searchForOtp(imap: ImapConnection, config: ImapConfig, minTimestamp?: Date): Promise<string | null> {
	return new Promise((resolve, reject) => {
		imap.openBox('INBOX', false, async (err: Error | null) => {
			// Guard: Check for openBox error
			if (err) return reject(err);

			const sinceDate = new Date(Date.now() - config.lookbackMinutes * 60 * 1000);

			imap.search([['SINCE', sinceDate]], async (err: Error | null, results: number[]) => {
				// Guard: Check for search error
				if (err) return reject(err);

				// Guard: Check if no results
				if (!results?.length) return resolve(null);

				try {
					const candidates = await fetchAndProcessEmails(imap, results, config);

					// Guard: No OTP candidates found
					if (candidates.length === 0) return resolve(null);

					// Filter by minimum timestamp if provided (to reject stale OTPs from previous attempts)
					// Apply a buffer to account for email delivery delay and clock skew
					const filteredCandidates = minTimestamp
						? candidates.filter((c) => c.timestamp.getTime() >= minTimestamp.getTime() - config.freshnessBufferMs)
						: candidates;

					// Guard: No fresh OTP candidates found
					if (filteredCandidates.length === 0) {
						console.log(
							`Found ${candidates.length} OTP email(s), but none are fresh enough. ` +
								`Minimum timestamp: ${minTimestamp?.toISOString()}, ` +
								`Latest OTP timestamp: ${candidates[0]?.timestamp.toISOString()}`
						);
						return resolve(null);
					}

					// Sort by newest first and return the most recent
					filteredCandidates.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());
					resolve(filteredCandidates[0]?.otp ?? null);
				} catch (error) {
					reject(error);
				}
			});
		});
	});
}

/**
 * Get Gmail App Password for user role (app passwords are per user, not per org)
 * @param role - User role
 */

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

function getGmailPasswordForRole(role: string): string {
	// Map role to Gmail App Password (same user = same password across orgs)
	const passwordMap: Record<string, string | undefined> = {
		'billing-admin': ENV.GMAIL_BILLING_ADMIN_APP_PASSWORD,
		admin: ENV.GMAIL_ADMIN_APP_PASSWORD,
		member: ENV.GMAIL_MEMBER_APP_PASSWORD,
	};

	const password = passwordMap[role];

	if (!password) {
		throw new Error(
			`No Gmail App Password configured for role="${role}". ` + `Check env var: GMAIL_${role.toUpperCase().replace(/-/g, '_')}_APP_PASSWORD`
		);
	}

	return password;
}

/**
 * Read OTP from Gmail
 * @param email - Email address to check
 * @param role - User role (for selecting correct Gmail App Password)
 * @param minTimestamp - Only accept OTPs from emails sent after this timestamp (prevents stale OTP usage)
 */

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

export async function readOtpFromGmail(email: string, role: string, minTimestamp?: Date): Promise<string | null> {
	const config = getOtpConfig();
	const gmailPassword = getGmailPasswordForRole(role); // App Password is per role, not per org

	return new Promise((resolve, reject) => {
		const imap: ImapConnection = new Imap({
			user: email,
			password: gmailPassword,
			host: 'imap.gmail.com',
			port: 993,
			tls: true,
			tlsOptions: { rejectUnauthorized: false },
			authTimeout: 10000,
		});

		const timeoutId: NodeJS.Timeout = setTimeout(() => {
			handleError(new Error(`IMAP operation timed out after ${config.timeoutMs}ms`));
		}, config.timeoutMs);

		const cleanup = () => {
			clearTimeout(timeoutId);
			if (imap?.state !== 'disconnected') {
				imap.end();
			}
		};

		const handleError = (err: Error) => {
			cleanup();
			reject(err);
		};

		const handleSuccess = (result: string | null) => {
			cleanup();
			resolve(result);
		};

		imap.once('ready', async () => {
			try {
				const otp = await searchForOtp(imap, config, minTimestamp);
				handleSuccess(otp);
			} catch (err) {
				handleError(err instanceof Error ? err : new Error(String(err)));
			}
		});

		imap.once('error', (err?: Error) => {
			handleError(err ?? new Error('Unknown IMAP error'));
		});

		imap.connect();
	});
}

