// Extract invitation link from email text or HTML

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

function extractInvitationLinkFromContent(text: string, html: string): string | null {
	// Try to extract from HTML first (more reliable)
	const htmlPatterns = [/href="(https:\/\/[^\/]+\/invite\?[^"]+)"/i, /href='(https:\/\/[^\/]+\/invite\?[^']+)'/i];

	for (const pattern of htmlPatterns) {
		const match = html.match(pattern);
		if (match?.[1]) return match[1];
	}

	// Fallback to text extraction
	const textPatterns = [/(https:\/\/[^\/]+\/invite\?invitation=[^\s]+)/i, /(https:\/\/[^\/]+\/invite\?[^\s]+)/i];

	for (const pattern of textPatterns) {
		const match = text.match(pattern);
		if (match?.[1]) return match[1];
	}

	return null;
}

// Extract org name from email subject

function extractOrgNameFromSubject(subject: string): string {
	// Subject format: "[DevRev] user@email.com has invited you to join OrgName Workspace"
	const match = subject.match(/has invited you to join (.+?)(?:\s+Workspace)?$/i);
	return match?.[1]?.trim() || '';
}


function sleep(ms: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

// Validate if email matches invitation criteria

function isValidInvitationEmail(
	fromText: string,
	subject: string,
	config: InvitationImapConfig,
	options?: { inviterEmail?: string; orgNameContains?: string }
): boolean {
	const fromLower = fromText.toLowerCase();
	const subjectLower = subject.toLowerCase();

	// Check basic criteria
	if (!fromLower.includes(config.fromContains.toLowerCase())) return false;
	if (!subjectLower.includes(config.subjectContains.toLowerCase())) return false;

	// Check optional filters
	if (options?.inviterEmail && !subjectLower.includes(options.inviterEmail.toLowerCase())) {
		return false;
	}

	if (options?.orgNameContains && !subjectLower.includes(options.orgNameContains.toLowerCase())) {
		return false;
	}

	return true;
}

// Process a single email message and extract invitation link if valid

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

async function processInvitationEmailMessage(
	raw: string,
	config: InvitationImapConfig,
	options?: { inviterEmail?: string; orgNameContains?: string }
): Promise<InvitationCandidate | null> {
	try {
		const parsed = await simpleParser(raw);

		const fromText = parsed.from?.text || '';
		const subject = parsed.subject || '';
		const text = parsed.text || '';
		const html = typeof parsed.html === 'string' ? parsed.html : '';
		const date = parsed.date ? new Date(parsed.date) : new Date();

		// Guard: Check if email matches criteria
		if (!isValidInvitationEmail(fromText, subject, config, options)) {
			return null;
		}

		// Guard: Extract invitation link
		const link = extractInvitationLinkFromContent(text, html);
		if (!link) return null;

		const orgName = extractOrgNameFromSubject(subject);

		return { link, timestamp: date, orgName };
	} catch {
		// Silently ignore parse errors
		return null;
	}
}

// Fetch and process all emails, returning invitation candidates

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

function fetchAndProcessInvitationEmails(
	imap: ImapConnection,
	results: number[],
	config: InvitationImapConfig,
	options?: { inviterEmail?: string; orgNameContains?: string }
): Promise<InvitationCandidate[]> {
	return new Promise((resolve, reject) => {
		const fetch = imap.fetch(results, { bodies: '', markSeen: false }); // Don't mark as seen
		const candidates: InvitationCandidate[] = [];
		let processedCount = 0;

		const checkCompletion = () => {
			processedCount++;
			if (processedCount === results.length) {
				resolve(candidates);
			}
		};

		fetch.on('message', (msg: ImapMessage) => {
			let raw = '';

			msg.on('error', () => {
				checkCompletion();
			});

			msg.on('body', (stream: NodeJS.ReadableStream) => {
				stream.on('data', (chunk: Buffer) => {
					raw += chunk.toString('utf8');
				});

				stream.once('end', async () => {
					const candidate = await processInvitationEmailMessage(raw, config, options);
					if (candidate) candidates.push(candidate);
					checkCompletion();
				});

				stream.once('error', () => {
					checkCompletion();
				});
			});
		});

		fetch.once('error', reject);
		fetch.once('end', () => {
			// All messages fetched, processing continues in stream.end
		});
	});
}

// Search for invitation emails and return most recent link

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

function searchForInvitationLink(
	imap: ImapConnection,
	config: InvitationImapConfig,
	minTimestamp?: Date,
	options?: { inviterEmail?: string; orgNameContains?: string }
): Promise<string | null> {
	return new Promise((resolve, reject) => {
		imap.openBox('INBOX', true, async (err: Error | null) => {
			// Guard: Check for openBox error
			if (err) return reject(err);

			const sinceDate = new Date(Date.now() - config.lookbackMinutes * 60 * 1000);

			imap.search([['SINCE', sinceDate]], async (err: Error | null, results: number[]) => {
				// Guard: Check for search error
				if (err) return reject(err);

				// Guard: Check if no results
				if (!results?.length) {
					console.log('No emails found in the lookback period');
					return resolve(null);
				}

				try {
					const candidates = await fetchAndProcessInvitationEmails(imap, results, config, options);

					// Guard: No invitation candidates found
					if (candidates.length === 0) {
						console.log(`Searched ${results.length} emails, no matching invitation found`);
						return resolve(null);
					}

					const freshnessBufferMs = config.freshnessBufferMs ?? 10_000;
					const filteredCandidates = minTimestamp
						? candidates.filter((c) => c.timestamp.getTime() >= minTimestamp.getTime() - freshnessBufferMs)
						: candidates;

					if (filteredCandidates.length === 0) {
						console.log(
							`Found ${candidates.length} invitation(s), but none are fresh enough. ` +
								`Minimum timestamp: ${minTimestamp?.toISOString()}, ` +
								`Latest: ${candidates[0]?.timestamp.toISOString()}`
						);
						return resolve(null);
					}

					// Sort by newest first and return the most recent
					filteredCandidates.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());
					const mostRecent = filteredCandidates[0];
					console.log(`Found ${filteredCandidates.length} fresh invitation(s), returning most recent for org: ${mostRecent?.orgName}`);
					resolve(mostRecent?.link ?? null);
				} catch (error) {
					reject(error);
				}
			});
		});
	});
}

/**
 * Read invitation link from Gmail
 *
 * Searches for DevRev invitation emails and extracts the invitation link.
 * Use this to automate accepting org invitations in tests.
 *
 * @param email - Email address to check (the invitee's email)
 * @param role - User role (for selecting correct Gmail App Password)
 * @param options - Optional filters and freshness control
 * @param options.minTimestamp - Only accept invitations sent after this timestamp
 * @param options.inviterEmail - Filter by inviter's email address
 * @param options.orgNameContains - Filter by partial org name match
 * @returns The invitation link or null if not found
 *
 * @example
 * const link = await readInvitationLinkFromGmail(
 *   'qa.testuser.devrev@gmail.com',
 *   'member',
 *   { orgNameContains: 'Autotest Computer' }
 * );
 * if (link) {
 *   await page.goto(link);
 * }
 */

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

async function readInvitationLinkOnceFromGmail(
	email: string,
	role: string,
	config: InvitationImapConfig,
	minTimestamp?: Date,
	options?: { inviterEmail?: string; orgNameContains?: string }
): Promise<string | null> {
	const gmailPassword = getGmailPasswordForRole(role);

	return new Promise((resolve, reject) => {
		const imap: ImapConnection = new Imap({
			user: email,
			password: gmailPassword,
			host: 'imap.gmail.com',
			port: 993,
			tls: true,
			tlsOptions: { rejectUnauthorized: false },
			authTimeout: 10000,
		});

		const timeoutId: NodeJS.Timeout = setTimeout(() => {
			handleError(new Error(`IMAP operation timed out after ${config.timeoutMs}ms`));
		}, config.timeoutMs);

		const cleanup = () => {
			clearTimeout(timeoutId);
			if (imap?.state !== 'disconnected') {
				imap.end();
			}
		};

		const handleError = (err: Error) => {
			cleanup();
			reject(err);
		};

		const handleSuccess = (result: string | null) => {
			cleanup();
			resolve(result);
		};

		imap.once('ready', async () => {
			try {
				const link = await searchForInvitationLink(imap, config, minTimestamp, options);
				handleSuccess(link);
			} catch (err) {
				handleError(err instanceof Error ? err : new Error(String(err)));
			}
		});

		imap.once('error', (err?: Error) => {
			handleError(err ?? new Error('Unknown IMAP error'));
		});

		imap.connect();
	});
}

import Imap from 'imap';
import { simpleParser } from 'mailparser';
import { ENV } from '@config/env.config';

export async function readInvitationLinkFromGmail(
	email: string,
	role: string,
	options?: {
		minTimestamp?: Date;
		inviterEmail?: string;
		orgNameContains?: string;
	}
): Promise<string | null> {
	const { minTimestamp, ...filterOptions } = options ?? {};
	const deadline = Date.now() + INVITATION_CONFIG.timeoutMs;
	let attempt = 1;

	while (Date.now() < deadline) {
		const remainingMs = deadline - Date.now();
		console.log(`Polling for invitation email (attempt ${attempt})...`);

		try {
			const link = await readInvitationLinkOnceFromGmail(
				email,
				role,
				{
					lookbackMinutes: INVITATION_CONFIG.lookbackMinutes,
					fromContains: INVITATION_CONFIG.fromContains,
					subjectContains: INVITATION_CONFIG.subjectContains,
					timeoutMs: Math.min(30_000, remainingMs),
					freshnessBufferMs: INVITATION_CONFIG.freshnessBufferMs,
				},
				minTimestamp,
				filterOptions
			);

			if (link) {
				console.log(`Invitation link found on attempt ${attempt}`);
				return link;
			}
		} catch (err) {
			console.log(`IMAP error on attempt ${attempt}: ${err instanceof Error ? err.message : String(err)}`);
		}

		if (Date.now() + INVITATION_CONFIG.pollIntervalMs >= deadline) {
			break;
		}

		await sleep(INVITATION_CONFIG.pollIntervalMs);
		attempt++;
	}

	console.log(`No fresh invitation email found after ${INVITATION_CONFIG.timeoutMs / 1000}s`);
	return null;
}

