/**
 * DevRev partition to AWS region mapping
 */
export const PARTITION_TO_REGION_MAP = {
	'us-1': 'us-east-1',
	'sg-1': 'ap-southeast-1',
	'au-1': 'ap-southeast-2',
	'eu-1': 'eu-central-1',
	'in-1': 'ap-south-1',
	'jp-1': 'ap-northeast-1',
} as const;

export type DevRevPartition = keyof typeof PARTITION_TO_REGION_MAP;
export type AWSRegion = (typeof PARTITION_TO_REGION_MAP)[DevRevPartition];

export function extractRegionFromConfig(config: Record<string, unknown>): string {
	// Primary method: Extract from CHORUS_SERVICE_WS_URL
	const chorusUrl = config.CHORUS_SERVICE_WS_URL as string | undefined;
	if (chorusUrl) {
		const match = chorusUrl.match(/dvrv-([a-z]{2}-\d)/);
		if (match?.[1]) {
			const partition = match[1] as DevRevPartition;
			const region = PARTITION_TO_REGION_MAP[partition];
			if (!region) {
				console.warn(`Unknown partition "${partition}" extracted from CHORUS_SERVICE_WS_URL`);
				return 'unknown';
			}
			return region;
		}
	}

	// Fallback: Extract from any DON (DevRev Object Name) in the config
	const configStr = JSON.stringify(config);
	const donMatch = configStr.match(/don:[^:]+:dvrv-([a-z]{2}-\d):/);
	if (donMatch?.[1]) {
		const partition = donMatch[1] as DevRevPartition;
		const region = PARTITION_TO_REGION_MAP[partition];
		if (!region) {
			console.warn(`Unknown partition "${partition}" extracted from DON`);
			return 'unknown';
		}
		return region;
	}

	console.warn('Could not detect region from config');
	return 'unknown';
}

/**
 * Maps a DevRev partition identifier to AWS region
 *
 * @param partition - DevRev partition (e.g., 'us-1', 'sg-1')
 * @returns AWS region string
 */
export function partitionToRegion(partition: string): string {
	return PARTITION_TO_REGION_MAP[partition as DevRevPartition] ?? 'unknown';
}

