import { test as baseTest } from '@fixtures/index.fixtures';

type TestArgs = Parameters<typeof baseTest>[1];
type TestBody = Parameters<typeof baseTest>[2];

/**
 * Conditionally registers a test only if the condition is true.
 * Use this instead of test.skip() to avoid inflating test counts with skipped tests.
 */
export function testIf(condition: boolean, title: string, testFn: TestBody): void;
export function testIf(condition: boolean, title: string, details: TestArgs, testFn: TestBody): void;
export function testIf(condition: boolean, title: string, detailsOrFn: TestArgs | TestBody, testFn?: TestBody): void {
	if (condition) {
		if (testFn) {
			baseTest(title, detailsOrFn as TestArgs, testFn);
		} else {
			baseTest(title, detailsOrFn as TestBody);
		}
	}
}

