/**
 * Test Data Utilities
 *
 * Helper functions for generating dynamic test data such as unique names,
 * timestamps, and other values to ensure test isolation and avoid collisions.
 */

/**
 * Generates a unique org name with a timestamp suffix
 * @param prefix - The prefix for the org name (default: 'Autotest Org')
 * @returns A unique org name like "Autotest Org 1720345678901"
 */

export function generateOrgName(prefix: string = 'Autotest Org'): string {
	const timestamp = Date.now();
	return `${prefix} ${timestamp}`;
}

/**
 * Converts an org name to its expected URL slug format
 * @param orgName - The display name of the organization
 * @returns The URL slug (lowercase, no spaces, no special characters)
 */

export function orgNameToSlug(orgName: string): string {
	return orgName
		.toLowerCase()
		.replace(/\s+/g, '')
		.replace(/[^a-z0-9]/g, '');
}

/**
 * Generates a unique org name and returns both the display name and slug
 * @param prefix - The prefix for the org name
 * @returns Object with name and slug properties
 */

export function generateOrg(prefix: string = 'Autotest Org'): { name: string; slug: string } {
	const name = generateOrgName(prefix);
	const slug = orgNameToSlug(name);
	return { name, slug };
}

/**
 * Generates a random string of specified length
 * @param length - The length of the random string (default: 8)
 * @returns A random alphanumeric string
 */

export function generateRandomString(length: number = 8): string {
	const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
	let result = '';
	for (let i = 0; i < length; i++) {
		result += chars.charAt(Math.floor(Math.random() * chars.length));
	}
	return result;
}

/**
 * Generates a unique email address for testing
 * @param prefix - The prefix for the email (default: 'autotest')
 * @param domain - The email domain (default: 'test.devrev.ai')
 * @returns A unique email like "autotest+1720345678901@test.devrev.ai"
 */

export function generateTestEmail(prefix: string = 'autotest', domain: string = 'test.devrev.ai'): string {
	const timestamp = Date.now();
	return `${prefix}+${timestamp}@${domain}`;
}

