import { test as setup } from '@playwright/test';
import { ENV } from '@config/env.config';
import { AppConfigObserver } from '@utils/config.utils';
import { navigateToComputerPage } from '@utils/page.utils';
import { loginWithOtp } from '@utils/auth.utils';
import { getComputerUserEmail } from '@utils/computer.utils';
import fs from 'fs';
import path from 'path';

const AUTH_DIR = '.auth';

setup('Computer - Authentication and Session Setup', async ({ page }, testInfo) => {
	// Get org and role from project metadata
	const metadata = testInfo.project.metadata as { org?: string; role?: string };
	const { org, role } = metadata;

	// Fail fast if metadata is missing
	if (!org || !role) {
		throw new Error(
			`FAIL FAST: Missing metadata in project "${testInfo.project.name}". ` +
				`Expected { org: string, role: string }, got: ${JSON.stringify(metadata)}. ` +
				`Check your playwright.computer.config.ts setup project definition.`
		);
	}

	const STORAGE_STATE_PATH = path.join(AUTH_DIR, `${ENV.TEST_ENV}-${org}-${role}-storageState.json`);

	// Initialize Config Observer
	const configObserver = new AppConfigObserver(page);
	configObserver.start();

	// Get email for this org + role (will throw if not found in YAML)
	const email = getComputerUserEmail(org, role);

	await navigateToComputerPage(page, { org });
	await loginWithOtp(page, { email, org, role });
	await page.waitForURL('**/computer', { timeout: 120_000 });
	await page.getByRole('img').first().waitFor({ state: 'visible', timeout: 90_000 });

	if (!fs.existsSync(AUTH_DIR)) {
		fs.mkdirSync(AUTH_DIR, { recursive: true });
	}

	await page.context().storageState({ path: STORAGE_STATE_PATH });

	const { appVersion, plugVersion, region } = await configObserver.getResult();
	configObserver.stop();

	fs.writeFileSync('app-version.txt', appVersion);
	fs.writeFileSync('plug-version.txt', plugVersion);
	fs.writeFileSync('region.txt', region);

	console.log(`Logged in as: ${email} (org=${org}, role=${role})`);
	console.log(`Saved storage state: ${STORAGE_STATE_PATH}`);
	console.log(`Saved APP_VERSION: ${appVersion}`);
	console.log(`Saved PLUG_VERSION: ${plugVersion}`);
	console.log(`Saved REGION: ${region}`);
});

