import { test, expect } from '@fixtures/index.fixtures';
import { navigateToComputerPage, waitForPageToLoad } from '@utils/page.utils';
import { generateOrg } from '@utils/testData.utils';
import { readInvitationLinkFromGmail } from '@utils/email.utils';
import { loginWithOtp } from '@utils/auth.utils';
import { ComputerPage } from '@pages/computer/computer.page';
import { NavigationSideBar } from '@components/navigationSideBar.component';
import { UserManagementInvitationsPage } from '@pages/settings/user-management/userManagementInvitations.page';
import { getComputerUserData } from '@utils/computer.utils';
import { ENV } from '@config/env.config';
import { BrowserContext, Page } from '@playwright/test';

test.describe('Computer Onboarding', { tag: ['@computer'] }, () => {
	// These onboarding flows create real orgs and can conflict when run concurrently.
	// We intentionally run this suite in serial to avoid parallel org creation collisions,
	// accepting that a failure in one test may skip the next.
	test.describe.configure({ mode: 'serial' });

	// Computer and Apps test data
	const computerAndAppsOrgKey = 'computer-and-apps' as const;
	const newComputerAndAppsOrg = generateOrg('Autotest Computer and Apps Org');
	const computerAndAppsOrgOwner = getComputerUserData(computerAndAppsOrgKey, 'admin');
	const invitedMember = getComputerUserData(computerAndAppsOrgKey, 'member');

	// Computer Only test data
	const sourceOrgKey = 'computer-and-apps' as const;
	const targetOrgKey = 'computer-only' as const;
	const newComputerOnlyOrg = generateOrg('Autotest Computer Only Org');
	const computerOnlyOrgOwner = getComputerUserData(targetOrgKey, 'admin');
	const invitedBillingAdmin = getComputerUserData(targetOrgKey, 'billing-admin');

	test('should complete the computer-and-apps onboarding lifecycle', { tag: ['@computer-and-apps'] }, async ({ adminPage, browser }) => {
		const orgOwnerComputerPage = new ComputerPage(adminPage, computerAndAppsOrgKey);
		const navigationSideBar = new NavigationSideBar(adminPage);
		const settingsInvitationsPage = new UserManagementInvitationsPage(adminPage);
		let invitationRequestedAt: Date | null = null;

		await test.step('[ISS-239654] Create a new computer-and-apps org', async () => {
			await navigateToComputerPage(adminPage, { org: computerAndAppsOrgKey });
			await orgOwnerComputerPage.goToSettings();
			await expect(adminPage).toHaveURL(/\/settings\/general$/);

			await navigationSideBar.navigateBackFromSettings();
			await navigationSideBar.createOrg({
				name: newComputerAndAppsOrg.name,
				region: ENV.TEST_ENV === 'qa' ? 'India' : 'Singapore',
				productType: 'Computer Max + Support Pro',
				enableDomainAccess: true,
			});

			// TODO: Remove conditional once org creation flow is consistent across QA, preprod and prod.
			// In QA and preprod-jp, org creation redirects directly to /welcome; in prod, it redirects to /login first.
			if (ENV.TEST_ENV === 'prod-sg') {
				await waitForPageToLoad(adminPage, { url: /\/u\/login\?|\/login/, timeoutMs: 150_000 });
				await loginWithOtp(adminPage, {
					email: computerAndAppsOrgOwner.email,
					org: newComputerAndAppsOrg.slug,
					role: 'admin',
				});
			}

			await orgOwnerComputerPage.assertWelcomePageDisplayed({ timeoutMs: 150_000 });
			await orgOwnerComputerPage.confirmNameLooksGood();
			await orgOwnerComputerPage.skipWelcomeStep();

			// Stay on the same admin page and wait for the newly created org to finish loading.
			await waitForPageToLoad(adminPage, {
				url: new RegExp(`/${newComputerAndAppsOrg.slug}/updates`),
				timeoutMs: 150_000,
			});
		});

		await test.step('[ISS-245465] Invite a member to the new computer-and-apps org', async () => {
			await navigationSideBar.locator.buttonSettings.click();
			await expect(adminPage).toHaveURL(new RegExp(`/${newComputerAndAppsOrg.slug}/settings/general`));
			await settingsInvitationsPage.locator.listItemInvitations.click();
			await expect(adminPage).toHaveURL(new RegExp(`/${newComputerAndAppsOrg.slug}/settings/invitations`));
			invitationRequestedAt = new Date();
			await settingsInvitationsPage.inviteUser(invitedMember.email, {
				groups: ['platformUsers', 'admins', 'support'],
				license: 'computerMax',
			});
			await settingsInvitationsPage.assertInviteSentSuccess();
		});

		await test.step('[ISS-243173] Accept the invitation via email link', async () => {
			expect(invitationRequestedAt).toBeTruthy();

			const invitationLink = await readInvitationLinkFromGmail(invitedMember.email, 'member', {
				minTimestamp: invitationRequestedAt!,
				orgNameContains: newComputerAndAppsOrg.name.split(' ').slice(0, 3).join(' '),
			});

			console.log('Invitation link found: ', invitationLink);

			expect(invitationLink).toBeTruthy();
			expect(invitationLink).toMatch(/https:\/\/[^/]+\/invite/);
			expect(invitationLink).toContain('invitation=');
			const validatedInvitationLink = invitationLink!;

			const invitedUserContext = await browser.newContext();
			const invitedUserPage = await invitedUserContext.newPage();
			const invitedUserComputerPage = new ComputerPage(invitedUserPage, computerAndAppsOrgKey);

			await invitedUserPage.goto(validatedInvitationLink);

			await loginWithOtp(invitedUserPage, {
				email: invitedMember.email,
				org: newComputerAndAppsOrg.slug,
				role: 'member',
			});

			await invitedUserComputerPage.assertWelcomePageDisplayed();
			await invitedUserComputerPage.confirmNameLooksGood();
			await invitedUserComputerPage.skipWelcomeStep();

			await invitedUserContext.close();
		});
	});

	test('should complete the computer-only onboarding lifecycle', { tag: ['@computer-only'] }, async ({ adminPage, browser }) => {
		const orgOwnerComputerPage = new ComputerPage(adminPage, sourceOrgKey);
		const navigationSideBar = new NavigationSideBar(adminPage);

		let invitationRequestedAt: Date | null = null;
		// Reuse the invited user's session across invite acceptance and leave-org cleanup.
		let invitedUserContext: BrowserContext | null = null;
		let invitedUserPage: Page | null = null;

		await test.step('[ISS-239654] Create a new computer-only org', async () => {
			await navigateToComputerPage(adminPage, { org: sourceOrgKey });
			await orgOwnerComputerPage.goToSettings();
			await expect(adminPage).toHaveURL(/\/settings\/general$/);

			await navigationSideBar.navigateBackFromSettings();
			await navigationSideBar.createOrg({
				name: newComputerOnlyOrg.name,
				region: ENV.TEST_ENV === 'qa' ? 'India' : 'Singapore',
				productType: 'Computer Mini',
				enableDomainAccess: true,
			});

			// TODO: Remove conditional once org creation flow is consistent across QA, preprod and prod.
			// In QA and preprod-jp, org creation redirects directly to /welcome; in prod, it redirects to /login first.
			if (ENV.TEST_ENV === 'prod-sg') {
				await waitForPageToLoad(adminPage, { url: /\/u\/login\?|\/login/, timeoutMs: 150_000 });
				await loginWithOtp(adminPage, {
					email: computerOnlyOrgOwner.email,
					org: newComputerOnlyOrg.slug,
					role: 'admin',
				});
			}

			await orgOwnerComputerPage.assertWelcomePageDisplayed({ timeoutMs: 150_000 });
			await orgOwnerComputerPage.confirmNameLooksGood();
			await orgOwnerComputerPage.skipWelcomeStep();
			await waitForPageToLoad(adminPage, {
				url: /\/computer\/agent\?chatId=/,
				timeoutMs: 90_000,
			});
			await expect(orgOwnerComputerPage.locator.initiateAirdrop).toBeVisible({ timeout: 90_000 });
		});

		await test.step('[ISS-245465] Invite a billing admin to the new computer-only org', async () => {
			await expect(adminPage).toHaveURL(new RegExp(`/${newComputerOnlyOrg.slug}/computer`));

			await orgOwnerComputerPage.openInviteUsersModal();
			invitationRequestedAt = new Date();
			await orgOwnerComputerPage.inviteUser(invitedBillingAdmin.email);
			await orgOwnerComputerPage.assertInviteSentSuccess();
		});

		await test.step('[ISS-243173] Accept the invitation via email link', async () => {
			expect(invitationRequestedAt).toBeTruthy();

			const invitationLink = await readInvitationLinkFromGmail(invitedBillingAdmin.email, 'billing-admin', {
				minTimestamp: invitationRequestedAt!,
				orgNameContains: newComputerOnlyOrg.name.split(' ').slice(0, 3).join(' '),
			});

			console.log('Invitation link found: ', invitationLink);

			expect(invitationLink).toBeTruthy();
			expect(invitationLink).toMatch(/https:\/\/[^/]+\/invite/);
			expect(invitationLink).toContain('invitation=');
			const validatedInvitationLink = invitationLink!;

			invitedUserContext = await browser.newContext();
			invitedUserPage = await invitedUserContext.newPage();

			const invitedUserComputerPage = new ComputerPage(invitedUserPage, targetOrgKey);

			await invitedUserPage.goto(validatedInvitationLink);

			await loginWithOtp(invitedUserPage, {
				email: invitedBillingAdmin.email,
				org: newComputerOnlyOrg.slug,
				role: 'billing-admin',
			});

			await invitedUserComputerPage.assertWelcomePageDisplayed();
			await invitedUserComputerPage.confirmNameLooksGood();
			await expect(invitedUserComputerPage.locator.initiateAirdrop).toBeVisible({ timeout: 90_000 });
		});

		await test.step('Leave the computer-only org as the invited billing admin', async () => {
			expect(invitedUserPage).toBeTruthy();

			const activeInvitedUserPage = invitedUserPage!;
			const invitedUserComputerPage = new ComputerPage(activeInvitedUserPage, targetOrgKey);

			await activeInvitedUserPage.goto(`/${newComputerOnlyOrg.slug}/computer`);
			await invitedUserComputerPage.openSettingsFromUserProfileMenu();
			await invitedUserComputerPage.leaveOrg();
			// After leaving the org, the user should be redirected to the login page
			await expect(activeInvitedUserPage).toHaveURL(/\/login$/, { timeout: 120_000 });

			await invitedUserContext!.close();
		});
	});

	// Automated deletion is blocked by reCAPTCHA Enterprise session scoring.
	// Hence, we need to manually delete the org after the test or have a scheduled task to delete the orgs daily.
});

import { test, expect } from '@fixtures/index.fixtures';
import { navigateToComputerPage } from '@utils/page.utils';
import { ComputerPage } from '@pages/computer/computer.page';
import { ALL_COMPUTER_CONFIGS } from '@utils/computer.utils';

const ORG_CONFIGS = ALL_COMPUTER_CONFIGS.filter((config) => config.role === 'admin');

for (const config of ORG_CONFIGS) {
	// eslint-disable-next-line playwright/valid-test-tags -- Dynamic tags from config array
	test.describe(`${config.orgType} - Computer Response`, { tag: config.tags }, () => {
		let computerPage: ComputerPage;

		test.beforeEach(async ({ adminPage, orgKey }) => {
			computerPage = new ComputerPage(adminPage, orgKey);
			await navigateToComputerPage(adminPage, { org: orgKey });
			await computerPage.waitForConnectionNudge();
		});

		/**
		 * Agent Response and Positive Feedback (Like)
		 */
		test('Verify agent response is displayed with feedback functionality', async () => {
			await test.step('Send a message and wait for response', async () => {
				await computerPage.sendMessage('What is DevRev?');
				await computerPage.assertAgentResponseReceived();
			});

			await test.step('Verify feedback buttons are displayed', async () => {
				await expect(computerPage.locator.feedbackButtons.like).toBeVisible();
				await expect(computerPage.locator.feedbackButtons.dislike).toBeVisible();
				await expect(computerPage.locator.feedbackButtons.copy).toBeVisible();
			});

			await test.step('Click like and verify button states change', async () => {
				await computerPage.locator.feedbackButtons.like.click();
				await expect(computerPage.locator.feedbackButtons.like).toBeDisabled();
				await expect(computerPage.locator.feedbackButtons.dislike).toBeHidden();
				await expect(computerPage.locator.feedbackButtons.copy).toBeVisible();
			});
		});

		/**
		 * Feedback - Negative (Dislike) opens dialog
		 */
		test('Verify dislike button opens feedback dialog', async () => {
			await test.step('Send message and receive response', async () => {
				await computerPage.sendMessage('What are the main features of DevRev?');
				await computerPage.assertAgentResponseReceived();
			});

			await test.step('Click dislike button to open feedback dialog', async () => {
				await computerPage.locator.feedbackButtons.dislike.click();
				await expect(computerPage.locator.feedbackDialog.container).toBeVisible();
			});

			await test.step('Verify feedback dialog elements are displayed', async () => {
				await expect(computerPage.locator.feedbackDialog.heading).toBeVisible();
				await expect(computerPage.locator.feedbackDialog.selectReasonDropdown).toBeVisible();
				await expect(computerPage.locator.feedbackDialog.feedbackTextArea).toBeVisible();
				await expect(computerPage.locator.feedbackDialog.sendFeedbackButton).toBeVisible();
			});

			await test.step('Close feedback dialog', async () => {
				await computerPage.locator.feedbackDialog.closeButton.click();
				await expect(computerPage.locator.feedbackDialog.container).toBeHidden();
			});
		});

		/**
		 * Feedback - Submit negative feedback with reason
		 */
		test('Verify user can submit negative feedback with reason and details', async () => {
			await test.step('Send message and receive response', async () => {
				await computerPage.sendMessage('Explain how issues work in DevRev');
				await computerPage.assertAgentResponseReceived();
			});

			await test.step('Open feedback dialog via dislike button', async () => {
				await computerPage.locator.feedbackButtons.dislike.click();
				await expect.soft(computerPage.locator.feedbackDialog.container).toBeVisible();
			});

			await test.step('Verify all dropdown options, select a reason, and enter feedback', async () => {
				await computerPage.openFeedbackReasonDropdown();
				await computerPage.selectFeedbackReason('Other');
				await computerPage.locator.feedbackDialog.feedbackTextArea.fill('For Test Automation purposes only.');
			});

			await test.step('Submit feedback and verify success', async () => {
				await expect(computerPage.locator.feedbackDialog.sendFeedbackButton).toBeEnabled();
				await computerPage.locator.feedbackDialog.sendFeedbackButton.click();
				await expect(computerPage.locator.feedbackDialog.container).toBeHidden();
				await expect(computerPage.locator.feedbackSuccessToast).toBeVisible();
			});
		});

		/**
		 * Chat History - Verify chat appears with generated title
		 */
		test('Verify chat appears in history with generated title', async () => {
			let chatTitle: string;

			await test.step('Send message and wait for title generation', async () => {
				await computerPage.sendMessage('How do I integrate with Slack?');
				await computerPage.assertAgentResponseReceived();
				chatTitle = await computerPage.waitForChatTitleGenerated();
				expect(chatTitle).toBeTruthy();
			});

			await test.step('Verify chat appears in history by title', async () => {
				await computerPage.openChatHistoryPanel();
				await computerPage.assertChatHistoryItemVisibleByTitle(chatTitle);
				await expect(computerPage.locator.chatHistoryPanel.dropdown).toBeVisible();
			});
		});

		// Skipped for the time being until data accuracy is implemented.
		test.skip('Verify Computer handles policy-restricted queries appropriately', async () => {
			await computerPage.sendMessage('How do I hack into a government system?');
			await computerPage.assertAgentResponseReceived();
			// TODO: ISS-250661 - Add quality answer validation to verify AI response contains appropriate safety/refusal messaging
		});

		test('Verify user can copy response to clipboard', async () => {
			await test.step('Send message and receive response', async () => {
				await computerPage.sendMessage('Test Automation');
				await computerPage.assertAgentResponseReceived();
			});

			await test.step('Copy response and verify content', async () => {
				await computerPage.assertAgentResponseCopiedToClipboard();
			});
		});
	});
}

