import fs from 'fs';
import { expect, test as setup } from '@fixtures/index.fixtures';
import { ENV } from '@config/env.config';
import { AppConfigObserver } from '@utils/config.utils';
import { waitForPageToLoad } from '@utils/page.utils';
import { getDefaultStorageStatePath } from '@utils/storageState.utils';

const AUTH_DIR = '.auth';

import fs from 'fs';
import { expect, test as setup } from '@fixtures/index.fixtures';
import { ENV } from '@config/env.config';
import { AppConfigObserver } from '@utils/config.utils';
import { waitForPageToLoad } from '@utils/page.utils';
import { getDefaultStorageStatePath } from '@utils/storageState.utils';

const STORAGE_STATE_PATH = getDefaultStorageStatePath(ENV.TEST_ENV);

setup('Login with username and password', async ({ page, navigationSideBar, loginWithEmailPage }) => {
	const orgSlug = ENV.ORG_SLUG;

	// Initialize Config Observer
	const configObserver = new AppConfigObserver(page);
	configObserver.start();

	await page.goto(`/${orgSlug}`);

	// Some regions (e.g., Japan) show a SAML/Google selection page before the Auth0 login.
	// Detect which page we land on and handle accordingly.
	const buttonSaml = page.getByRole('button', { name: 'Continue with SAML' });
	const auth0EmailField = loginWithEmailPage.locator.auth0Email;

	await expect(buttonSaml.or(auth0EmailField)).toBeVisible({ timeout: 150_000 });

	if (await buttonSaml.isVisible()) {
		await buttonSaml.click();
	}

	await waitForPageToLoad(page, { url: /\/u\/login\?|\/login/, timeoutMs: 150_000 });
	await loginWithEmailPage.loginWithPassword(ENV.LOGIN_EMAIL!, ENV.LOGIN_PASSWORD!);

	await waitForPageToLoad(page, { url: new RegExp(`/${orgSlug}/updates`), timeoutMs: 120_000 });
	await expect(navigationSideBar.locator.dropdownUserProfile).toBeVisible({ timeout: 90_000 });

	// Save Storage State
	if (!fs.existsSync(AUTH_DIR)) fs.mkdirSync(AUTH_DIR, { recursive: true });
	await page.context().storageState({ path: STORAGE_STATE_PATH });

	const { appVersion, plugVersion, region } = await configObserver.getResult();
	configObserver.stop();

	fs.writeFileSync('app-version.txt', appVersion);
	fs.writeFileSync('plug-version.txt', plugVersion);
	fs.writeFileSync('region.txt', region);

	console.log(`Saved APP_VERSION: ${appVersion}`);
	console.log(`Saved PLUG_VERSION: ${plugVersion}`);
	console.log(`Saved REGION: ${region}`);
});

