			await test.step('Verify tooltip on hover', async () => {
				await pieChart.hoverFirstSliceAndAssertTooltip();
			});

			await test.step('Toggle legend item off', async () => {
				await pieChart.assertLegendItemEnabled(SEVERITY_LEVELS.high);
				await pieChart.assertVisibleSliceCount(3);

				await pieChart.toggleLegendItem(SEVERITY_LEVELS.high);
				await pieChart.assertLegendItemDisabled(SEVERITY_LEVELS.high);
				await pieChart.assertVisibleSliceCount(2);
				await expect(page).not.toHaveURL(/drillthrough/);
			});

			await test.step('Toggle legend item back on', async () => {
				await pieChart.toggleLegendItem(SEVERITY_LEVELS.high);
				await pieChart.assertLegendItemEnabled(SEVERITY_LEVELS.high);
				await pieChart.assertVisibleSliceCount(3);
			});
		});

		test('should navigate to drillthrough when clicking pie slice', async ({ dashboard }) => {
			const ticketsDashboard = dashboard(DASHBOARD_NAME);
			const pieChart = ticketsDashboard.getPieChartWidget(WIDGETS.pieChart);

			await pieChart.clickFirstSliceForDrillthrough();
			await ticketsDashboard.assertDrillthroughNavigated(WIDGETS.pieChart);
		});
	});

	test.describe('Table Widget', () => {
		test('should display table with all columns, controls, and menu', async ({ page, dashboard }) => {
			const ticketsDashboard = dashboard(DASHBOARD_NAME);
			const table = ticketsDashboard.getTableWidget(WIDGETS.table);

			await test.step('Setup: ensure all columns are visible', async () => {
				await table.showColumns(TABLE_COLUMNS);
			});

			await test.step('Verify table title and container', async () => {
				await expect(table.locator.title).toBeVisible();
				await expect(table.locator.table).toBeVisible();
			});

			await test.step('Verify column headers', async () => {
				await table.assertColumnHeadersVisible(TABLE_COLUMN_HEADER_PATTERNS);
			});

			await test.step('Verify table controls', async () => {
				await expect(table.locator.groupDropdown).toBeVisible();
				await expect(table.locator.customizeDropdown).toBeVisible();
				await expect(table.locator.menuButton).toBeVisible();
			});

			await test.step('Verify group dropdown menu', async () => {
				await table.locator.groupDropdown.click();
				await expect(page.getByRole('menu', { name: /Group/ })).toBeVisible();
				await table.locator.title.click();
			});

			await test.step('Verify customize dropdown options', async () => {
				await table.assertCustomizeOptionsVisible(TABLE_COLUMNS);
			});

			await test.step('Verify widget menu', async () => {
				await table.openMenu();
				await table.assertMenuIsDisplayed();
			});
		});

		test('should support grouping, column customization, and drillthrough', async ({ dashboard }) => {
			const ticketsDashboard = dashboard(DASHBOARD_NAME);
			const table = ticketsDashboard.getTableWidget(WIDGETS.table);

			await test.step('Grouping: filter table by stage values', async () => {
				const stageColumn = 'Tickets.Stage';

				await table.resetGrouping();
				await table.selectGroupOption(stageColumn);
				await expect(table.locator.groupDropdown).toContainText(stageColumn);

				await table.getGroupItem(STAGES.awaitingDevelopment).click();
				await table.assertColumnValuesEqual({ columnName: stageColumn, expectedValue: STAGES.awaitingDevelopment });

				await table.getGroupItem(STAGES.awaitingProductAssist).click();
				await table.assertColumnValuesEqual({ columnName: stageColumn, expectedValue: STAGES.awaitingProductAssist });

				await table.getGroupItem(STAGES.inDevelopment).click();
				await table.assertColumnValuesEqual({ columnName: stageColumn, expectedValue: STAGES.inDevelopment });

				await table.getGroupItem(STAGES.queued).click();
				await table.assertColumnValuesEqual({ columnName: stageColumn, expectedValue: STAGES.queued });

				await table.getGroupItem(STAGES.workInProgress).click();
				await table.assertColumnValuesEqual({ columnName: stageColumn, expectedValue: STAGES.workInProgress });

				await table.resetGrouping();
			});

			await test.step('Column customization: show and hide severity column', async () => {
				const severityColumn = 'Tickets.Severity';

				await table.showColumn(severityColumn);
				await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeVisible();
				await table.assertColumnVisible(severityColumn);

				await table.hideColumn(severityColumn);
				await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeHidden();
				await table.assertColumnHidden(severityColumn);

				await table.showColumn(severityColumn);
				await expect(table.getColumnHeader(/Tickets.Severity/i)).toBeVisible();
				await table.assertColumnVisible(severityColumn);
			});

			await test.step('Drillthrough: click row to navigate', async () => {
				await table.clickRowForDrillthrough();
				await ticketsDashboard.assertDrillthroughNavigated(WIDGETS.table);
			});
		});
	});
});

