import { test, expect } from '@fixtures/index.fixtures';
import { FEATURE_TOGGLES } from '@config/featureToggles.registry';
import { ENV } from '@config/env.config';
import { setFeatureToggle } from '@utils/controlPanelFeatureToggles.utils';
import { navigateToUpdatesPage, openGlobalSearch } from '@utils/page.utils';

test.describe('Issue Creation - Commenting - Editing', { tag: ['@smoke', '@feature-toggle'] }, () => {
	test.describe.configure({ mode: 'serial' });

	test.describe('Via Modal (feature toggle enabled)', { tag: ['@ft-quick-create-modal-enabled'] }, () => {
		let issueId: string;

		test.beforeAll(async ({ browser }) => {
			// Control panel is inaccessible on prod-sg/preprod-jp; quick create modal is already the default there
			if (ENV.TEST_ENV === 'prod-sg' || ENV.TEST_ENV === 'preprod-jp') return;

			// Explicitly enable modal — <nil> behavior is org-dependent during gradual rollout
			const { context } = await setFeatureToggle(browser, {
				featureToggle: FEATURE_TOGGLES.QUICK_CREATE_MODAL_ENABLED,
				value: 'true',
			});
			await context.close();
		});

		test('Create a new issue via modal', async ({ page, navigationSideBar, quickCreateModal, sidePanel }) => {
			await navigateToUpdatesPage(page);

			const dateTimeNow = Date.now();
			const issueTitle = `Issue - Automation ${dateTimeNow}`;
			const issueDescription = `This is an issue created for Playwright Automation for date time: ${dateTimeNow}`;

			await navigationSideBar.clickCreateNew('Issue', {
				waitFor: quickCreateModal.locator.dialog.or(quickCreateModal.locator.onboardingHeading),
			});
			await quickCreateModal.dismissOnboardingIfPresent();
			await quickCreateModal.toBeDisplayed();
			await quickCreateModal.fillOutForm({
				title: issueTitle,
				description: issueDescription,
				owner: 'QT Qa Testuser (Me)',
				part: 'Default Product 1',
			});
			await quickCreateModal.locator.buttonCreate.click();

			// Assert that a new issue id is displayed in the side panel
			await expect(sidePanel.issue.locator.buttonIssueId).toBeVisible();
			issueId = await sidePanel.issue.getIssueId();
		});

		test('Comment on an issue (modal flow)', async ({ page, globalSearchModal, sidePanel }) => {
			const dateTimeNow = new Date().toISOString();
			const comment = `This is an automated comment for ${issueId}. Date: ${dateTimeNow}`;

			await navigateToUpdatesPage(page);
			await openGlobalSearch(page);

			await globalSearchModal.searchAndVerifyResultById(issueId);

			await globalSearchModal.clickSearchResultById(issueId);
			await sidePanel.toBeDisplayed();

			await sidePanel.issue.assertIssueIdDisplayed(issueId);
			await sidePanel.issue.addComment(comment);

			await sidePanel.issue.assertCommentDisplayed(comment);
		});

		test('Edit a key field on an issue (modal flow)', async ({ page, globalSearchModal, sidePanel }) => {
			await navigateToUpdatesPage(page);
			await openGlobalSearch(page);

			await globalSearchModal.searchAndVerifyResultById(issueId);

			await globalSearchModal.clickSearchResultById(issueId);
			await sidePanel.toBeDisplayed();
			await sidePanel.issue.assertIssueIdDisplayed(issueId);

			await sidePanel.issue.updateAttributes({
				priority: 'P3',
				stage: 'Completed',
				tag: 'smoke',
			});

			// Cleanup
			await sidePanel.issue.deleteIssue(issueId);
			await page.close();
		});
	});

	test.describe('Via Side Panel (feature toggle disabled)', { tag: ['@ft-quick-create-modal-disabled'] }, () => {
		// eslint-disable-next-line playwright/no-skipped-test -- Control panel inaccessible on these envs; experience.ui_quick_create_modal_enabled cannot be set
		test.skip(
			ENV.TEST_ENV === 'prod-sg' || ENV.TEST_ENV === 'preprod-jp',
			'Side panel flow unavailable — control panel inaccessible on this environment'
		);

		let issueId: string;

		test.beforeAll(async ({ browser }) => {
			// Set toggle to false so issue creation opens a side panel instead of a modal
			const { context } = await setFeatureToggle(browser, {
				featureToggle: FEATURE_TOGGLES.QUICK_CREATE_MODAL_ENABLED,
				value: 'false',
			});
			await context.close();
		});

		test('Create a new issue via side panel', async ({ page, navigationSideBar, sidePanel }) => {
			await navigateToUpdatesPage(page);

			const dateTimeNow = Date.now();
			const issueTitle = `Issue - Automation ${dateTimeNow}`;
			const issueDescription = `This is an issue created for Playwright Automation for date time: ${dateTimeNow}`;

			await navigationSideBar.clickCreateNew('Issue', { waitFor: sidePanel.locator.panel });
			await sidePanel.toBeDisplayed();
			await sidePanel.createIssue.fillOutForm({
				title: issueTitle,
				description: issueDescription,
				owner: 'QT Qa Testuser (Me)',
				part: 'Default Product 1',
			});
			await sidePanel.createIssue.locator.buttonCreate.click();

			// Assert that a new issue id is displayed
			await expect(sidePanel.issue.locator.buttonIssueId).toBeVisible();
			issueId = await sidePanel.issue.getIssueId();
		});

		test('Comment on an issue', async ({ page, globalSearchModal, sidePanel }) => {
			const dateTimeNow = new Date().toISOString();
			const comment = `This is an automated comment for ${issueId}. Date: ${dateTimeNow}`;

			await navigateToUpdatesPage(page);
			await openGlobalSearch(page);

			await globalSearchModal.searchAndVerifyResultById(issueId);

			await globalSearchModal.clickSearchResultById(issueId);
			await sidePanel.toBeDisplayed();

			await sidePanel.issue.assertIssueIdDisplayed(issueId);
			await sidePanel.issue.addComment(comment);

			await sidePanel.issue.assertCommentDisplayed(comment);
		});

		test('Edit a key field on an issue', async ({ page, globalSearchModal, sidePanel }) => {
			await navigateToUpdatesPage(page);
			await openGlobalSearch(page);

			await globalSearchModal.searchAndVerifyResultById(issueId);

			await globalSearchModal.clickSearchResultById(issueId);
			await sidePanel.toBeDisplayed();
			await sidePanel.issue.assertIssueIdDisplayed(issueId);

			await sidePanel.issue.updateAttributes({
				priority: 'P3',
				stage: 'Completed',
				tag: 'smoke',
			});

			// Cleanup
			await sidePanel.issue.deleteIssue(issueId);
			await page.close();
		});

		test.afterAll(async ({ browser }) => {
			// Restore toggle to 'true' (modal) — the desired default for test environments
			const { context } = await setFeatureToggle(browser, {
				featureToggle: FEATURE_TOGGLES.QUICK_CREATE_MODAL_ENABLED,
				value: 'true',
			});
			await context.close();
		});
	});
